INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('3e6d7ab7-b3c2-4220-9b0d-2f5dd5c3d8b4', '012605dd-177d-48c6-9717-490e7ef05b30', '0b1718b8-d5c0-40b5-8c62-6d826434ce45', 5.0, 'inspired', NULL, 0, NULL, NULL, '2026-03-14 03:20:42', '2026-03-14T03:39:41.008Z', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-001', 'seed-reviewer-001', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 4.5, 'inspired', NULL, 0, NULL, NULL, '2026-03-13 13:46:06', '2026-03-13 13:46:06', '<p>Absolutely <b>loved</b> this book. The characters felt so real and the writing pulled me in from the first page.</p><p>I couldn''t put it down — stayed up way too late finishing it. The ending was <span class="spoiler-tag" data-spoiler="true">completely unexpected and left me in tears, especially when the main character finally confronted the truth about their past</span>.</p><p>Highly recommend for anyone who loves <i>emotionally rich</i> storytelling.</p>', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-002', 'seed-reviewer-002', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 3.0, 'contemplative', NULL, 0, NULL, NULL, '2026-03-09 13:46:06', '2026-03-09 13:46:06', '<p>It was fine. The prose was solid but the pacing dragged in the middle third. I kept waiting for something to happen and it didn''t really pick up until the last fifty pages.</p><p>That said, it gave me a lot to think about afterward. Sometimes the slow ones stick with you.</p>', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-003', 'seed-reviewer-003', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 2.5, 'angry', NULL, 1, NULL, NULL, '2026-02-28 14:46:06', '2026-02-28 14:46:06', '<p>I really wanted to like this but I couldn''t get past the halfway point. The writing felt clunky and the plot went nowhere.</p><p>Maybe it gets better but life is too short for books that don''t grab you.</p>', 45, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-004', 'seed-reviewer-004', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 5.0, 'devastated', NULL, 0, NULL, NULL, '2026-02-12 14:46:06', '2026-02-12 14:46:06', '<p>I am <b>wrecked</b>. This book destroyed me in the best possible way.</p><p>The way the author builds up to <span class="spoiler-tag" data-spoiler="true">the sacrifice at the end — when you realize the whole story was leading to this one impossible choice</span> is just masterful storytelling.</p><p>I ugly-cried on public transit. <i>No regrets.</i></p><ul><li>Characters: perfection</li><li>Plot: devastating</li><li>Would I read again? In a heartbeat</li></ul>', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-005', 'seed-reviewer-005', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 3.75, 'lighthearted', NULL, 0, NULL, NULL, '2025-12-14 14:46:06', '2025-12-14 14:46:06', '<p>Fun, breezy read. Not going to change your life but it doesn''t need to. Sometimes you just want a book that makes you smile and this delivers.</p><p>The humor lands more often than it misses and the characters are charming even when they''re being ridiculous.</p>', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('seed-review-seed-reviewer-006', 'seed-reviewer-006', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 4.0, 'contemplative', NULL, 0, NULL, NULL, '2026-03-11 14:42:31', '2026-03-11 14:42:31', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('55aab934-ad04-4af7-a551-e7e5955d469b', '012605dd-177d-48c6-9717-490e7ef05b30', 'da1b3889-6a00-44a4-b643-ea4625b4fbcf', 3.5, 'devastated', NULL, 0, NULL, NULL, '2026-03-15 01:38:13', '2026-03-15 01:38:13', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('d20267e8-e140-4854-af1d-e29ff639702e', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '83c7c591-02d7-49cc-ac3f-a516434c0a09', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-20T02:36:33.005Z', 'I loved the expansive worldbuilding and the presence of romance without it being a central theme of the entire plot.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2c7727f2-0318-49f2-b3fa-8a9e713a9c29', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'db514228-8092-4813-80be-07b825b12fb7', 4.75, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-20T02:36:33.023Z', 'The Hunger Games was the series that got me back into reading as a 20-something, and I''m really grateful it did! I''ve re-read and re-listened to it countless times, and I find myself wanting to see Katniss'' success more more and more every time I read it. I enjoy that it stays dark and serious, yet still manages to inspire me to support the rebels of 12 (even before they know they''re rebels). I also adore both Peeta and Gale, and I think the way the potential love interests were developed was really well-done.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e771f0b7-39c8-4e6a-aa6a-36d0ee697c51', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'b1554002-560e-49e5-8608-d913431cadc0', 4.25, NULL, NULL, 0, 4, 2025, '2025-04-21T12:00:00.000Z', '2026-03-20T02:36:38.725Z', 'I enjoyed this one so much! There’s a lot that would normally make me not love it — slower pacing, not super high stakes, etc. — but Jobson somehow drew me in and made me look forward to turning on this audiobook as often as I could.

The MC and supporting characters are all distinctive, interesting, and people I wanted to know more about. He unfolded the world and the stakes of the plot in a way that left me craving more but that was never too fast or slow.

It’s absolutely a cozy read, so if you’re looking for something with high stakes and filled with action, this one probably isn’t a read for right now. But it definitely scratches the itch for something both interesting and enjoyable without being overwhelming. Another LitRPG win!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('0260a237-270e-459d-9838-92c7b004b7a9', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'd8cda49e-f3c6-44a1-bdf6-3af0e9f420d6', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-17 14:14:05', 'I''ve been a huge Potterhead since around my junior year of high school! While the first book in the series is very childlike and not the best of the bunch, I''m so grateful for the immersive universe and incredibly relatable and charming characters.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('7a5285aa-e800-4856-8eae-69270c6833e6', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '41e92797-3468-4ea8-96d8-98dc24d80151', NULL, NULL, NULL, 1, NULL, NULL, '2026-03-17 14:14:05', '2026-03-17 14:14:05', 'Lots of sexual content. Commentary about how the “real world” is so terrible because “insert leftist ideology.” So much swearing it’s hard to read. I just didn’t care about the story and I’d finished over 20%.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2432cefe-e1bc-4bf5-b26b-d1f1c98ded21', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'a8d411c6-5b8d-41ff-8ec7-0ddd36eb2030', 4.5, NULL, NULL, 0, 5, 2025, '2025-05-04T12:00:00.000Z', '2026-03-18T20:10:24.906Z', 'It’s a different type of book for me, but I really liked this one! The pacing was fast, the humor was spot-on, and the book didn’t try to take itself too seriously.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('c9a6b262-4564-441f-97fb-d2240a2c49f1', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '338af347-9cfc-495f-8c8e-6d35766c5f1f', 4.75, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:25.327Z', 'This was my favorite standalone book for many years! It was the first adult novel that got me interested in reading more than just what I was assigned for school. The dark, brooding nature of the antagonist contrasts really beautifully against the hopeful innocence of the protagonist and his family. It''s one book I''d love to own a signed copy of one day because of its significance in my life!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('3b5312f4-d06b-4628-9a0c-032461614b8b', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '93971173-94a6-46d6-b814-76dee8924aa0', 5.0, NULL, NULL, 0, 9, 2025, '2025-09-03T12:00:00.000Z', '2026-03-18T20:10:26.342Z', 'One of the best books I have ever read! Action-packed from the first page, and I could not put it down. (And I just finished book 7 about 3 weeks after starting the first — I literally couldn’t wait to turn every page!)', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f2f53b92-db16-4dc6-b368-6bc083e51269', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '925b5f7a-b845-4a90-9d14-55b33544f0a2', 4.5, NULL, NULL, 0, 3, 2025, '2025-03-01T12:00:00.000Z', '2026-03-18T20:10:28.578Z', 'I loved the semi-unserious attitude the main character speaks with. I also really enjoy reading books adapted for film. The relationships were really interesting in this book, and the cliffhanger ending left me wanting more.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('d9726721-f01b-4e13-93f3-730506bccdd5', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '2594f76d-3278-4b3d-9253-c16b8bcb0293', 1.5, NULL, NULL, 0, 9, 2025, '2025-09-03T12:00:00.000Z', '2026-03-18T20:10:30.613Z', 'I wanted a cozy, weird, dystopian read. Instead, I was treated to a cacophony of leftism barely disguised as a fun story about robots.

I love this book cover. The concept of robots running a noodle shop in post-war San Francisco is, on its face, a fun conceit. And the book length makes it an easy read between longer books.

But despite the fact that I *already* spend more time than the average person to try reading only books I’ll enjoy, the lack of proper labeling (IMO) meant that I didn’t know what I was getting into was a very politically charged portrayal of how it feels to be transgender in 2025 and why Donald Trump and MAGA are bad.

Write that if it’s what you want. But why is it masquerading as a cozy read? It’s… not. I want to read content that doesn’t feel like Twitter-fueled rage.

The prose is well-done, but the story falls apart because it’s not really about the story. It’s about a “message,” and if you’re tired of hearing that “message” lately, I would steer clear of this.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('de9ff70e-d39e-482c-a838-2276c40fb625', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '69089ed2-46a2-4b34-9801-6d31a77a79fd', NULL, NULL, NULL, 1, NULL, NULL, '2026-03-17 14:14:05', '2026-03-17 14:14:05', 'I hated the overkill of erotica. I thought the story was interesting, but it was way too much like just reading porn.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('ba1cbb0f-e950-4ae9-9250-b8ccecf5a657', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '303d53f0-26bb-48de-87c1-10e05f271f17', 4.5, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:37.813Z', 'Another win from this author for me! It’s less expansive, plot wise, than the first series in the DFZ by Rachel Aaron, but I still enjoyed the slow burn and fantastic world building.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('8bd56410-a48d-4f9a-a624-8cedc3e74f29', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'cf8a7374-1c6f-465e-92b9-ff358c4782ac', 3.0, NULL, NULL, 0, 3, 2025, '2025-03-27T12:00:00.000Z', '2026-03-18T20:10:37.872Z', 'It’s incredibly well-written, but the depressing gore, random open-door sex scene, and sad ending make this book not one for me.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('fe81f530-3375-439b-a525-cf869574248a', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '362433ea-52c6-4435-a7e3-9e02af7cdfcd', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:45.507Z', 'I''ve re-listened to this audiobook many times. I love the characters, the development Ender experiences during his learning, and the twisted way the main plot concludes.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('970b75b4-ab94-4b78-b770-cb97fd3ddd62', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '7ef3bc1d-513e-4e30-b2c5-098a8fad7f87', 2.25, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:46.964Z', 'Ready Player One was a favorite of mine, but I found this sequel to be obnoxious to the point that I doubt I’ll re-read it again. The main character’s growth, albeit minimal, in the first story, is entirely undone in the opening few chapters of Ready Player Two. There is pandering to an LGBTQ+ audience that was entirely absent from the first book, and it feels like it was inserted to meet some sort of quota, rather than to be a meaningful representation of underrepresented classes. The story itself is much less interesting than the first book, too — it is essentially a repeat, in many ways, of the first story’s plot, but without the broad scale. The book ends with a deux ex machina that solves the entire problem of the book, and the plot device used has nothing to do with the main character. It just felt like the author got lazy and inserted easy ‘wins’ rather than making the plot interesting and allowing the characters to grow to pay off earlier topics.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2a0f56d4-0edd-4992-ab3d-62c96e441156', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '8bc74c00-0882-43d8-a123-9e8e2db74c65', 5.0, NULL, NULL, 0, 8, 2024, '2025-04-25T12:00:00.000Z', '2026-03-18T20:11:11.864Z', 'One of my favorite reads in a long time! It kept me guessing the whole time, and I was quickly drawn to every character as they were introduced. Fantastic development. I also appreciated that the book was rather clean and sparingly used even profanity, completely skipping over the sexual content for which there was certainly opportunity.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('61efc12c-8412-4015-88e5-86df5701fe5e', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'a98a80ed-b283-4427-b45b-f4ac9bff28ee', 3.5, NULL, NULL, 0, 8, 2025, '2025-08-17T12:00:00.000Z', '2026-03-18T20:10:49.018Z', 'Prose: 0.75/1
Development: 1.25/2
Preference: 1.25/2

I love some LitRPG, but this one was hard for me. The pacing was super slow, and it didn’t really feel like there was a clear direction for the plot until the very end. I wanted to like it more, but won’t be continuing the series.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('9591b5db-b2f9-4f3f-a968-663fbebd0eee', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'a053d40d-00be-4c7e-8e81-76d9c0beb26c', 2.5, NULL, NULL, 0, 4, 2025, '2025-04-19T12:00:00.000Z', '2026-03-18T20:10:49.415Z', 'The world building was really roughly developed and difficult to immerse myself in, and the FMC’s constant, paralyzing fear of an attempted SA in her past was confusing at best.

In some ways, this book just wasn’t a good fit for me — the slow burn romance was absolutely the central plot point, and that’s not really the kind of thing I enjoy reading.

I appreciated that it did stay clean, as marketed, and I do think there were a lot of good bones to the story. The author nailed the twist ending. But it could have really benefited from a more thorough developmental edit.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f94eb36a-9362-43c6-8c0c-188d9afaf6a2', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '94b31229-6d32-4f1e-ba74-ee9425ee3824', 4.5, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:50.407Z', 'I read non-fiction maybe once a year, but this one was worthwhile (and I''ve read it twice over the last several years). It was a very inspiring experience, especially as I read it after being laid off from a ''dream job'' and not knowing how to begin dreaming again.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('eebf8486-5e51-47b3-9483-3b776fbc9924', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '50ab0939-81f6-4c27-8590-240e57e6c06b', 3.0, NULL, NULL, 0, 7, 2024, '2024-07-07T12:00:00.000Z', '2026-03-18T20:10:56.146Z', 'This was a book I WANTED to love more than I ACTUALLY loved it. The premise is intriguing — every 4 years, the remaining members of humanity have their memories wiped clean. This is thought to prevent war, hatred, and all manner of vile human behavior.

However, the story''s scale felt somehow very limited because of the self-imposed design of the story. This might be due to the fact that it''s the first of a series, but it felt like there was very little monumental payoff for the price offered by the main characters.

Overall, it was an okay read, but I wasn''t overly impressed enough to consider re-reading it anytime soon.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('ff1724d4-fcd2-43d3-9ba7-f233cdd7b95d', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'b6c9c39a-4c60-4cad-b2f0-d0ee808d40d1', 4.5, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:57.781Z', 'I love The Reckoners series! The worldbuilding felt unique and engaging, and the story kept me hooked from the beginning. I enjoyed the fast pace, and I thought the unfolding of the plot twists was done really well.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('772a1630-9a05-473e-b927-cd6cb65ba749', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '79e9ad14-f708-4001-8c78-8d1f66bd78b7', 4.75, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:58.818Z', 'The audiobook for this is a consistent re-listener for me. I love Mark Watney''s scientific genius delivered with biting, sarcastic humor. I was brought to tears by the emotional reunion he experiences as the book closes, and it was absolutely a book I never wanted to put down!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('276e3d89-586b-48a1-a466-f8b140f76e3d', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '0b1718b8-d5c0-40b5-8c62-6d826434ce45', 5.0, NULL, NULL, 0, 8, 2024, '2024-08-09T12:00:00.000Z', '2026-03-18T20:10:59.132Z', 'This is one of my favorite books of all time! It''s interesting from page one, and the twists and turns make it even better. It''s great for science nerds like me, but the story and characters are incredibly engaging regardless of how much you enjoy geeking out.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('37eb6044-14f3-491b-a57f-96ea8b86659e', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '77a9946d-e973-4b4a-90dc-73b207a7bc84', 1.0, NULL, NULL, 0, 6, 2025, '2025-06-01T12:00:00.000Z', '2026-03-18T20:10:59.535Z', 'This book should have been such an easy 5-star read for me — funny, fast, and about kaijus on another planet.

Instead, it’s 2/3 progressive politics — for some reason?! — and 1/3 poorly written monster lore. It takes until the final ~50 pages of the book to get to a legitimate plot, and I couldn’t tell you anything about what the kaijus look like except “big” and “with parasites”

Genuinely, I wanted to DNF this book in the first chapter based solely on the wildly unnecessary political commentary (and everyone loves to think about COVID, right?!). I only kept going because a) it was so short and b) I was convinced he couldn’t CONTINUE with that commentary and c) I wanted to write a legitimate review.

I understand if you’re not into conservative politics. But if that’s what you want to talk about, just be honest about it and WRITE ABOUT THAT; don’t create a thinly veiled YouTube rant disguised as a monster “pop song.”', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f32a836f-2879-417c-a7b1-0d7ccd437df8', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'bc062c13-d5e6-4a57-a969-f3e9761864dc', 5.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:10:59.570Z', 'The original Red Rising trilogy is absolutely tied one other series as an all-time favorite! I love the characters, the absolutely unexpected twists and turns, and the political intrigue that doesn''t become so broad it''s impossible to follow. I can''t say enough good about this book!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('9f07f134-1306-44e8-b1e6-db4b669172d8', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '6a5c90d7-e607-427b-afef-8e8c0471cb6c', 5.0, NULL, NULL, 0, 6, 2025, '2025-06-05T12:00:00.000Z', '2026-03-21T02:05:43.847Z', 'Literally, how does this book get away with being so good?! Red Rising vibes, but somehow a completely separate sort of story. I love the MC for <span class="spoiler-tag" data-spoiler="true">being not another “omg I never knew I was perfect at everything” repeat.</span> The story hooked me. It was absolutely impossible to put down. And the ENDING! Holyyyyy cow. Out of nowhere. 

I can’t say enough good. Absolute banger.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('d6776f0b-00c5-44c6-8e45-6e94461112e7', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '4943ecb0-529a-4653-928e-c1e1fe9c9448', 4.25, NULL, NULL, 0, 7, 2025, '2025-07-06T12:00:00.000Z', '2026-03-18T20:11:05.192Z', 'This is one of my favorite re-readers! I love the focus on nerdy lore, from D&D to video games and everything in between. The only reason I didn’t rate it higher is because the character tends to be very whiny and self-centered, and he doesn’t grow much as a person throughout the book. The experience was positive in spite of the main character, rather than because of him.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('394a712c-49fa-4ab1-b9e6-7fdbf58a9740', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '243ec99b-0051-4701-940d-c15e86eba9f4', 4.25, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:11:08.918Z', 'I loved learning more about President Snow''s origins, and I found myself constantly intrigued by the next thing Lucy Gray Baird would say or do. The development of the Hunger Games themselves was a fascinating take on a follow-up to such a beloved trilogy. I found myself fascinated by the morally grey mindset of Coriolanus Snow, and even as his evil nature was exposed, a big part of me wanted to see some sort of satisfying ending to his and Lucy Gray''s bizarre love story. I liked the unanswered questions of the ending, too.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('7b51242f-2a66-4ea0-b473-2784323dc4b2', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '6f3cb7f0-0d2f-4af9-87c5-7e000f92c931', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:11:10.431Z', 'This was a great read! I adore the math and physics side of this nerdy sci-fi, and I enjoyed it enough to read it in a single sitting. My only complaint was that the final 10-15% of this book moved too quickly compared to the rest, making the ending feel somewhat rushed compared to the way the rest of the plot was laid out.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('25b5a610-2c16-42a4-a28f-374ad07a0259', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '2806006f-c855-4c5f-a7ab-1c6ae5e63883', 3.75, NULL, NULL, 0, 3, 2025, '2025-03-01T12:00:00.000Z', '2026-03-18T20:11:10.440Z', 'I adore all of the books in Panem, but this one was my least favorite of the five. As much as I was engaged with Haymitch''s story in a way I didn''t want to put the book down, I found there to be two things that genuinely bugged me that made me rate this lower than I would rate the other books in this world. One, an important plot point <spoiler>(Haymitch''s quick and almost completely unexplained interest in joining a rebellion led by Plutarch)</spoiler>felt way too easy rather than a well-developed storyline. Two, the appearance of so many characters we knew from the original trilogy of Songbirds and Snakes started to get really heavy-handed and, honestly, felt more like lazy fan fiction than the creation of new and complex characters that I''m accustomed to getting from Collins. By the time she introduced <spoiler>Effie Trinket</spoiler>, I was genuinely frustrated and wanted to meet new and different characters.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('5de636bc-0d12-4a76-ac39-ed71135773e8', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '5b39369d-e7dd-40d5-9f4a-bde8df20aeed', 3.0, NULL, NULL, 0, 8, 2025, '2025-08-31T12:00:00.000Z', '2026-03-18T20:11:10.441Z', 'This book had some good bones as a silly fantasy read — it’s funny, the MC is an absolute goober, and the concept is unique.

However, the story was all over the place, there were several very unclear events/plot points, and the main conflict was introduced at 71% of the way through the book (resolved at ~97%).

It’s a fast read, and the writing is simple enough that it’s not difficult to finish. But I think a heavier hand in editing could have really made it a blast to read, rather than something I finished because it wasn’t very long.

DISCLAIMER: I was given a free eARC copy of this book in exchange for an honest review.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('926739aa-1545-49d1-ad43-37272fdd917f', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '1f8dac82-35e9-41f9-84f1-eb4ed3ea2474', 4.25, NULL, NULL, 0, 3, 2026, '2026-03-08T12:00:00.000Z', '2026-03-18T20:11:13.945Z', 'I get nervous about self-published works, but this absolutely stands out. There were some editing problems (about 3x where scenes repeated with different versions), but I still really enjoyed the read! It’s based in a real scientific problem, not woke ideology masked as a story, and it’s well-written.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('9b6b2b0a-5cb2-488a-b291-db64987c9315', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '5c91301d-7495-4930-a18c-78da7035abe4', 5.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-17 14:14:05', 'This is my FAVORITE of the entire Harry Potter series! The development of Voldemort''s early life through memories is the strongest part of the plot for me, but in general, I loved the way the author was able to unfold shocks and surprises despite the familiarity of the characters by this point in their Hogwarts education. The antagonist was really interesting (especially the very morally grey way he operates), and the book felt more mature than its "middle-grade" tag, which I appreciated since it felt like these books grew with their main characters.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('3d586b82-1313-4702-98fc-52d48083d915', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'c7a32044-f108-48cf-ae9a-06b68fc7b573', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:14:05', '2026-03-18T20:11:15.049Z', 'The massive stakes of this plot dragged me in from the first page. It was slower-paced, which can be hit or miss for me, but I loved the way the story progressed through so much plot as well as time. I also really enjoyed the nerdy science angle of this one with so much description of how the book''s opening scene would be handled using contemporary science, astronomy, and space travel tech.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('970f097a-4925-42f5-9e49-3d6660f7619e', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'dbec0eab-3a90-48ab-89db-b4d78b64eb1e', NULL, NULL, NULL, 1, NULL, NULL, '2026-03-17 14:14:05', '2026-03-17 14:14:05', 'The writing was very clunky and so many plot points were introduced at once in a way that felt overwhelming and confusing. I didn''t see myself feeling connected in any way to the MC, and I didn''t think I''d be able to connect to the story for those reasons.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('97d0f063-4ed6-40d4-ae6f-f84c857a3d2e', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'c0eda33e-01fd-4610-b21f-b7b28c99f9ab', 3.0, NULL, NULL, 0, 6, 2025, '2025-06-01T12:00:00.000Z', '2026-03-18T20:11:16.693Z', 'I was very bought into the concept, but the execution left something to be desired. I think the story could have benefited from fewer main characters or a bit more development of the story.', NULL, '', 0, 'user');
