INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('39bdfc33-d796-446d-a139-908cbfad3eae', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'dd17436c-c6b1-4e93-807a-87029694e82d', 4.75, NULL, NULL, 0, NULL, NULL, '2026-03-17 14:40:51', '2026-03-18T20:10:28.231Z', 'This is a major re-reader for me! I adore the characters, I deeply appreciate the well-developed magic system, and I think it’s an interesting take on societal systems without feeling political or preachy.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('67fe3ddc-8879-4a57-b4fd-09d2c2e7c7f9', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', 'e53e17b1-bc6a-4615-8049-4a25b37211c7', 3.5, NULL, NULL, 0, NULL, NULL, '2025-03-01T12:00:00.000Z', '2026-03-17 14:40:51', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('bebacb00-a546-452e-9215-64c20e5b8d0a', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'f8d4122f-2d57-4a02-900b-ada7d355729b', 4.0, NULL, NULL, 0, 12, 2021, '2021-12-09T12:00:00.000Z', '2026-03-17 23:30:21', 'I cannot remember if I had ever read this book as a kid or not, so I’m going to treat it like a first time read. 

I do, however, remember my freshly-turned 12-year-old self seeing it in the theatres on Christmas Day 2005 & being absolutely blown away. 

Between the many rewatches of the movie & the countless Sunday school lessons mentioning it, I have pretty much every step of the story memorized. So I was a less than surprised by the twists & turns. 

I can’t review the storyline as much for that reason, but I can say one thing: if children’s theology was a genre, this book would be the definitive title. 

Lewis’ ability to break down theology (Mere Christianity) on a doctorate level is only matched by his ability to explain it allegorically in a way that children can understand. 

Some lines of this story (“‘Course he isn’t safe. But he’s good.” for example) will stick with me for a long time. 

It’s a quick, easy read, but it’s written in a way that becomes more complex as you chew on it. Classic fantasy isn’t everyone’s cup of tea, but Lewis did something here that may never be redone. 

I’m very excited to dive into the next six books, which I do not remember nearly as well.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('55db2c1c-a5d4-4598-9359-b9daed32e9d8', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '0b1718b8-d5c0-40b5-8c62-6d826434ce45', 5.0, NULL, NULL, 0, 2, 2026, '2026-02-26T12:00:00.000Z', '2026-03-20T00:52:48.486Z', 'This book is exactly what sci-fi should be. 

Doesn’t have much readability for me? No. However, it made me feel too much to give it anything less than five stars. 

That is genuinely all I can say without giving spoilers. 

This is also the first time I’ve ever read a book exclusively on audiobook. I can’t believe I was actually able to pay attention to an audiobook. Wild!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('8a6f881c-f18b-463a-88ab-2f828841c3d8', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '6fd605bc-66e3-4479-a539-6b6aef575f8e', NULL, NULL, NULL, 0, 2, 2026, '2026-02-25T12:00:00.000Z', '2026-03-17 23:30:21', 'Alternate title: Gavin & the Terrible, Horrible, No Good, Very Bad Day. 

This one was a roller coaster. Not in quality but in emotion. 

The growth in Kip was so fun to witness little by little. He’s becoming the hero Gavin was but also never could be. 

Cruxer will make my all time character list. He had a few more moments in this book that had me cheering. 

Also, Teia, Karris, The White. And all the twists at the end that I genuinely didn’t even see coming! 

The hardest part of this is waiting until I get home tog ran book 4! 

Can’t decide if it’s my favorite or second favorite so far. I’ll need some time to process it.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('18f17276-e4b1-496f-a28f-9ec3e7a519d2', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '83a9ade3-360a-4e4f-b070-9e0040ca9d6f', 5.0, NULL, NULL, 0, 1, 2026, '2026-01-13T12:00:00.000Z', '2026-03-20T00:52:48.518Z', 'This ending has me wigging out! 

I do think this book was a slight improvement on book 1, even though they were both easy five star reads. 

Liv went from one of my favorite POVs to the chapters I dreaded the least. 

Any chapter taking place around The Color Prince had me counting the pages, but that probably just says something about how little I care for villains. 

Kip’s growth through this book was such an incredible experience that I was nearly jumping out of my seat for the last six chapters. He’s becoming an all-timer for me. 

The plot twists at the end had my jaw dropping. I can’t think of an author that has done that so successfully in nearly every book he’s written. From all four Night Angel novel to both Lightbringer books I’ve read thus far, he’s really had me enthralled. 

Ironfist & Teia both became very dear to me within these pages & I look forward to spending more time with the for three more books. I’m genuinely dreading the day that I will have nothing new from this world to read.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('c2916e93-04ed-44e8-b5b2-ec50d74da959', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '72fce70b-416d-449b-acd5-4e28ecf467de', 5.0, NULL, NULL, 0, 12, 2025, '2025-12-03T12:00:00.000Z', '2026-03-20T00:52:48.527Z', 'What an experience! I couldn’t put it down! Spent the second half of NaNoWriMo struggling to write my own while obsessing over this one. 

It’s been a while since I’ve read a book where I genuinely enjoyed every character. Flawed as they are, I rooted for them all. Kip. Live. Gavin. Karris. Corbin. Ironfist. 

This book made me laugh & cry & drop my jaw. The amount of bombs in the last 25 pages had aching to pick up the second one. 

This was an easy five stars & it will slip into my all time list. We’ll see as I finish the whole series how many fall among the top for me.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('ec40e53d-d3ad-403b-ac4a-814e17954660', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e7995c7b-79c5-4cf7-b09e-87094939bede', 4.0, NULL, NULL, 0, 11, 2025, '2025-11-15T12:00:00.000Z', '2026-03-20T00:52:48.528Z', '[SPOILER]
Issue 150 hit me so hard. The culmination of years of my life wrapped into one beautifully bittersweet conclusion. 

It was the longest volume by far & I still finished the whole thing in just over 24 hours. I had to know how it ended! 

There were two things that keeps this from retuning to the five star form of the Tom Waltz run:

1. Oddly enough—and I can’t believe I’m saying it—the Waltz issues were the worst part of this entry. 

The Armageddon Game was teased for a couple dozen issues as this grand chess game with multiple villains & it ended up being a one-issue long battle. I found it disappointing. 

2. After the incredible issue that ended the main storyline, I was left with a five issue mini series. It wasn’t bad, but it lessened the emotional impact of seeing the story end the way 150 closed it all up. 

The final 13 issues of the main run were with the ride of admission. This is still the definitive version of the Teenage Mutant Ninja Turtles.
[/SPOILER]', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('a772e544-7061-4f6b-b0f2-cba78b826e61', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a8db900d-3b76-4228-b58a-ec9f9f0741c8', 3.0, NULL, NULL, 0, 11, 2025, '2025-11-13T12:00:00.000Z', '2026-03-20T00:52:48.528Z', 'The fantasy equivalent of pulp science fiction. 

I had as much fun with this book for the first two acts as I had with all of Streams of Silver, but the final third felt fairly exhausting. 

The relationships between the characters are forced & rushed. I found myself confused at every interaction that Catti-Brie had with both Drizzt & Wulfgar. But then again, am I reading Forgotten Realms books for romance? 

The adventure was fun. The creatures they encountered were bizarre. The action was solid. It was a fun book about Drizzt & I really have no complaints. I also doubt I’ll ever read it again though. 

All in all, the final two entries of this trilogy served their purpose: fun ‘90s fantasy that put a smile on my face.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('df78469b-67b7-486d-9423-04c77aaf3067', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'dff989bf-0efb-47c8-9271-e20dcbba6db9', 3.0, NULL, NULL, 0, 10, 2025, '2025-10-30T12:00:00.000Z', '2026-03-20T00:52:48.530Z', 'I read this book very slowly, a few chapters here & there with my quiet time in the mornings. I wanted to slowly digest it & dwell on it alongside scripture. 

Given the time in which it was written, the translation required, & the subject matter at hand, it was a struggle for much of it. 

But the parts that jumped out to me were incredible. 

“Whatever lacked this name, no matter how learned and polished and veracious it was, could not wholly capture me.” 
book 3, chapter 4 (Cicero’s Incluence)

I appreciate how much Confessions changed Latin literature. It is truly one of the most influential pieces of writing in not just the Church but the world. Anyone giving blatantly bad reviews simply cannot see beyond the surface. It wasn’t a fun read, but it was an important one that I’m glad to have completed.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('a99ef2a8-5692-4f78-a0e3-c000f590faa6', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e01cf599-a511-4974-b062-43eb5d7bc18a', 4.0, NULL, NULL, 0, 10, 2025, '2025-10-29T12:00:00.000Z', '2026-03-20T00:52:48.531Z', 'I’m really torn between 4 & 5 stars for this one. 

I’ve never had my enjoyment jump quite this drastically between the first & second installment of a series. 

While I struggled to get through The Crystal Shard, I had to convince myself to put Streams of Silver down. I had a few very late nights with this one in my hands. 

I wouldn’t say the quality changed all that much. It is still very clearly a 1980s fantasy novel. 

I took a sizable gap between the two books, so I can’t dissect my contrast between my levels of enjoyment too much, but there were a few aspects that jumped out to me. 

1. Adding Catti-Brie’s POV to the villain chapters helped make those less of a slog. I cared so little about Akar Kessell in The Crystal Shard that devoting entire chapters to him almost ruined the book alone. And while Artemis Entreri is more interesting, Catti-Brie still helped that pacing issue for me. 
2. The party stayed together. Seeing the dynamics of the main four characters really drove him the personalities & arcs at work. I wasn’t in love with any characters before this book. Now I can say that I love all of our mainstays. You could truly feel the found family element this time around. 
3. I’ve never seen a movie contain the word, copse, this much.

It was a roller coaster from beginning to end. It truly felt like a DnD campaign. Why more could I ask for from Salvatore? It was a blast!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('a9ccc79b-460d-40c3-a9ac-0a3812524cbb', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '24674cb3-b14c-4f83-9fbe-26ec9d758c30', 4.0, NULL, NULL, 0, 10, 2025, '2025-10-20T12:00:00.000Z', '2026-03-20T00:52:48.532Z', 'This is the most I’ve enjoyed a volume since Tom Waltz left. 

It did feel more like a setup to the last part of the IDW story. A lot of exposition & splitting up the party to bring them all back together for a big battle. 

One volume away from the end & I’m very excited to pick in up!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('8e82728b-4088-4bec-a98d-352dfc3f2b89', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'b2c45f9f-d771-48b8-b988-a3eb3255eff8', 2.0, NULL, NULL, 0, 10, 2025, '2025-10-08T12:00:00.000Z', '2026-03-20T00:52:48.558Z', 'This is not a good book. 

The prose felt at a third grade reading level. 

Every character was just so intolerable. 

It got slightly intriguing for a few chapters before changing POVs & getting even worse than before. 

This twist was so ridiculously stupid that I was waiting to find out it was a dream. I can’t believe that would have been an improvement. 

Judging by the average rating, is this really good for contemporary fiction? Are they all this bad? 

Maybe I’m just not the target demographic. 

Anyway, back to epic fantasy for me!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e2e6ab98-406b-49a3-8be3-01f17c3d17a8', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a68842cc-c9a0-4489-a8c3-c57b01961461', 4.0, NULL, NULL, 0, 10, 2025, '2025-10-04T12:00:00.000Z', '2026-03-20T00:52:48.569Z', 'Three opinions about Night Angel Nemesis:

1. I hate first person narrations, especially when it’s gimmicky like this. 
2. This book was 200-300 pages longer than it needed to be. 
3. I love Brent Weeks enough that the first two points don’t matter.

It’s been so long since I’ve gasped at the end of a book. Masterful work here. 

I missed all the characters from The Night Angel Trilogy so much, especially Logan & Vi. I do wish we’d seen more of them both, but the major players all stayed true to themselves & it was like revisiting old friends. The new character fit right in as well! 

The villain truly upped the stakes from the last books & I was glued to the page from start to finish not I hadn’t gotten married two weeks after starting it, I would’ve flown through it just like the other Weeks books!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f8a3c958-c50e-45c4-8c6b-43744b713e21', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '429bb0cc-13f7-441a-be3e-836c77cbd2c8', 4.0, NULL, NULL, 0, 8, 2025, '2025-08-31T12:00:00.000Z', '2026-03-20T00:52:48.581Z', 'Let’s put aside the fact that this was the most physically beautiful book I’ve ever read. 

Isles of the Emberdark really grew on me.

Part one was a bit of a chore. The flashbacks really threw off the pacing for me, but I’m not sure if there was a better way to have done it, except maybe just including Sixth of the Dusk in the beginning separately. 

I found the world interesting but a little boring compared to most Cosmere works. But once Starling & her crew showed up, I was fully on board. It was like the Cosmere’s very own Firefly crew & I was eating it up! 

The message was uplifting, the characters were a mixed bag but most fun, & the villain was delightfully hatable. 

An intriguing look into the future of the Cosmere while being a really great time on its own! Solid four star read!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f72e7e0e-5574-465a-991d-2a44c7a9772f', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'badf4d52-2a5c-41e2-a8a4-7ff659d7c078', 4.0, NULL, NULL, 0, 8, 2025, '2025-08-23T12:00:00.000Z', '2026-03-20T00:52:48.594Z', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('af68e421-bc39-49eb-b304-3a9d75f851c2', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd188604b-d03f-43ba-ac6c-9e1c4b59a8b2', 4.0, NULL, NULL, 0, 8, 2025, '2025-08-23T12:00:00.000Z', '2026-03-20T00:52:48.606Z', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('bbc13586-8cd2-47e3-bddc-ca85763cd5d5', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'cb183ae7-0f4d-404b-88e2-7ff9efd04826', 4.0, NULL, NULL, 0, 5, 2022, '2022-05-21T12:00:00.000Z', '2026-03-20T00:52:48.618Z', 'This is the most blown away I’ve ever been by the end of a series! Sanderson definitely had every aspect of this story planned out from page one of book one. Things I never expected to play a significant part coming out of left field in ways that made me feel stupid for not expecting it. If I’m honest, I was confused as to how he could’ve even continued this series after the first book was so brilliant on its own, but I happily stand corrected! 

This is definitely the best book of the series. Not my personal favorite, but definitely the most impressive on a technical level. 

The most impressive part of this book is his ability to take characters I didn’t really care about in significant ways (Spook, TenSoon) & make them my favorites. I would look ahead to see which chapters were going to be about them. Not that characters like Vin & Elend weren’t exciting as well.

All around, this book a page turner. Over 2200 pages in the trilogy & every word was worth making it to this end. The amount of times I was left with my jaw dropped while reading it is enough for me to recommend it & leave this five star review with no reservations!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('316f25e9-ab97-4b49-bf3b-7d5c1ebd0ca4', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e5713fac-7f78-4239-b322-e46b0a4535e9', 4.0, NULL, NULL, 0, 9, 2022, '2022-09-19T12:00:00.000Z', '2026-03-20T00:52:48.628Z', 'Going into Warbreaker, the back of the book felt a little reminiscent of Elantris. A princess being sent to marry into another nation’s royal family, a man becoming an immortal without knowing why, & religious beliefs on the brink of war. 

I found out quickly how wrong I was though! 

This is my favorite Cosmere book since Mistborn era 1. (I’m reading Stormlight next though!) 

There wasn’t a single character that was a weak link. They were all three dimensional. I felt like inreallungot to know them, but all the twists with them felt shocking yet organic. 

The worldbuilding was top-notch as always. It all just came across as real. That’s what I’ve been appreciating most about Sanderson on my trek through the Cosmere! 

The biggest twist was spoiled for me because I googled a character to see the appearance better. But it was still such a satisfying ending! 

I definitely still have my fervor to continue this journey!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('37cfbafd-f200-4674-99dd-07d4b36fb4e1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'b382f13b-8626-447d-b8a1-55711f680d85', 3.0, NULL, NULL, 0, 8, 2022, '2022-08-25T12:00:00.000Z', '2026-03-20T00:52:48.643Z', 'The best word to describe this one: fun! 

I’m sure I would feel very different if I’d gone straight to this one from era 1, but after a little break from Scadrial, it was so nice to revisit these magic systems! The updates in technology over the 300 years made for such an interesting revelation for the metal-based abilities that I was intrigued by every move they made. 

I don’t think I’ve ever laughed out loud at a book as much as this one as well. Wax & Wayne have a great chemistry & Marasi’s inability to reply to most of Wayne’s comments made for great comedic timing. I don’t really feel that attached to the characters yet, but that process has begun. 

Was it perfect? No. Was it Sanderson’s best work? Not even close. Was it a fun ride that has me excited for the sequel? Absolutely!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('3705c863-fe13-49c0-b213-110b1dc1b8f8', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '582ea620-c8b7-44a8-8071-5f84f2a9781c', 4.0, NULL, NULL, 0, 9, 2022, '2022-09-06T12:00:00.000Z', '2026-03-20T00:52:48.657Z', 'I really wish I’d held off on reading era 2 until The Lost Metal was released. That ending! 

I can officially say I’m in love with these characters. Now, most of them are very static characters. Honestly, all of them probably are. An argument could be made for Marasi being dynamic, but she doesn’t really change as much as just achieves goals. 

It was nice to see the whole gang together for an adventure in this one. Wax, Wayne, Marasi, & Steris (along with some characters that may be spoilers for the first two books). But once again, the shining beacon of this book was Wayne; he feels like fantasy’s version of Holden Caulfield & I’m completely down for it! His little adventure when he’s on his own feel like short stories in & of themselves, almost in the vein of Tales of Ba Sing Se (for my ATLA fans out there). 

I can’t say much without spoiling it, but this one was quite a wild ride & it has me so excited for book 4!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('fcdf0c14-aabc-402c-b9b0-fa026b3c82ae', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '32b3d408-8093-4f25-8d2b-3d2f0731d276', 5.0, NULL, NULL, 0, 2, 2023, '2023-02-18T12:00:00.000Z', '2026-03-20T00:52:48.673Z', 'I thought Dawnshard was a big improvement over Edgedance, but not for the reason most people do. 

I like Lift, contrary to popular opinion. However, Rysn is probably my favorite interlude character in the main series. I was pretty excited to see her get a novella of her own. 

Thaylen culture is one of the more interesting on Roshar, so I definitely loved the little bit of extra worldbuilding here. I also loved the entirely new culture (which reminded me of Mistborn’s Kandra) they introduced. 

Rysn & The Lopen we’re fantastic characters to explore & the plot of this one was engaging yet simple. It was everything I want from Stormlight novellas & it leaves me fully prepared to jump into Rhythm of War!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('67857f4b-9fd0-4463-b70b-9637f6db911b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '1eb6be8c-1e98-435f-8f33-839da2dadcef', 4.0, NULL, NULL, 0, 12, 2023, '2023-12-14T12:00:00.000Z', '2026-03-20T00:52:48.686Z', 'This book will fit snuggly into the #4 spot in my Cosmere rankings. I wasn’t aware how much I needed a fantasy Mad Max story! 

It was a pretty slow start, but once it took off, it really took off! 

The Stormlight adjacent aspects had my internally squealing & I’m more than ready to see the effects of this book in Stormlight 5 next year! 

The side characters weren’t anything genre-breaking, but I was genuinely rooting for them. The villain, however, was interesting in that his goal was pretty cliché, but his skillset did not match it. It made for such a satisfying ending in most ways. And the unsatisfying parts were exactly what they were meant to be. 

Easy five stars!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('1b535034-da77-4dd5-b552-ed446ad4b814', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '6418e03b-9441-4efc-8950-0d3bd4922a3a', 4.0, NULL, NULL, 0, 12, 2023, '2023-12-28T12:00:00.000Z', '2026-03-20T00:52:48.701Z', 'It had been a little over a year since I’d read Bands of Mourning. Man, I’d forgotten how much I loved these characters. Wax, Wayne, Marasi, Steris. 

Wayne is one of my favorite Cosmere characters & this book really showcased his character for me. 

The expansion of the worldbuilding continued through these last two books was brilliant. And the expansion of the Cosmere as a whole. (I don’t want to give spoilers, so I’ll just say you should read at least the first three Stormlight books before this one.)

The stakes were bigger than ever, but they also got even more personal for the entire crew. All four of them had to figure out who they really were & what they really wanted. It was emotional & satisfying, like watching my friends finally start chasing their dreams. 

I’m so curious as to what Brando Sando has in store for era 3!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('da8f6c4c-420b-42ca-aa6d-bcaad5fab30a', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '1ac6fe55-369f-40c9-946d-bd0962caddf5', 5.0, NULL, NULL, 0, 5, 2024, '2024-05-13T12:00:00.000Z', '2026-03-20T00:52:48.715Z', 'As far as the story goes, I would give this book a 3/5. It doesn’t really feel like anything happens. And then it just kind of ends. I wouldn’t say it was unsatisfying, but it just wasn’t memorable. 

The characterizations, however, are an easy 5/5. The things that were teased through the first two books come to fruition here in near perfection. The psyche of Lock Lamora is explored in a fresh way that feels so natural. It was another entry of a book series that just feels like I’m hanging out with my friends. And that will always be what Lynch does best. 

After Red Seas Under Red Skies, it was nice to have a return to quality flashbacks. I actually preferred them to the main story in this entry. 

I’m not sure how I feel about the twist, but we’ll see how that all plays out in future installments (if they ever come).

The lackluster story mixed with the incredible characters evens this book out to a 4/5 for me. And you can bet I’ll have The Thorn of Emberlain preordered as soon as I can!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('9b1c0e7a-eb65-4314-8ed4-42de35c4a954', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '39ef1cb5-a199-4695-b008-cdb0daed7ad1', 4.0, NULL, NULL, 0, 8, 2024, '2024-08-21T12:00:00.000Z', '2026-03-17 23:30:34', 'The recommendations of this book were correct; this is the best prose I’ve ever read. There were moments where a single line made my heart drop. I cannot give enough praise to Rothfuss on his ability to keep a reader engaged. 

The pacing of the story varied, but it was obviously intended. The slow parts came together to make sense in the end. The small story arcs that seemed inconsequential became major plot points later on. I felt like I was putting together I wonderful puzzle by reading this book. It took everything in me to keep from cheering for the last 75 pages! 

I didn’t care for the third person sections of Kvothe telling the story to the Chronicler, but they were so short that I didn’t have to push past them very often. 

This was certainly just a part of an origin story & I’m eager to pick up A Wise Man’s Fear. This is certainly going to slip its way into my all time top ten list of books.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('7c5e73c5-8238-47fb-9257-596ba555912b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '4c277765-81ae-419c-add1-254dcc48dbfe', 4.0, NULL, NULL, 0, 3, 2025, '2025-03-17T12:00:00.000Z', '2026-03-17 23:30:34', 'I got about five chapters into this one & was already annoyed at the fact that I was going to have to update my all time favorite books list. 

My only regret is that I put this series so far down on my TBR. 

There were a few flaws: the similar or hard-to-pronounce names & the romantic interactions. But they were hardly noticed among the plethora of positives: the characters, the worldbuilding, the epic scale, the history, the magic system. 

I’m about the open up The Great Hunt now to pick up right where I left off. 

For the record, my favorite characters right now are Rand, Egwene, Mat, & Loial. We’ll see how consistent that remains over the next 13 books.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('abdfa21b-2e70-45f7-9e50-f38dfb605c88', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '0897c86c-42be-4630-945d-f3baf6ea7c6a', 4.0, NULL, NULL, 0, 4, 2025, '2025-04-04T12:00:00.000Z', '2026-03-17 23:30:34', 'Once again, I couldn’t put it down & I’m going to try to appreciate that until I get to The Slog. 

The worldbuilding is so top notch here. Every place they go genuinely feels new & fresh. I see how nearly every modern fantasy book I love stemmed from this style of storytelling. There were a few towns they visited in this one that had me so intrigued & disappointed when they left for the next one. 

The characters are all fleshing out. Even the ones I didn’t like are coming together in such wonderful ways. 

The romance, however, is exactly what I’ve always heard. Every single couple is a woman randomly fighting off undying love for a man with which she’s never had a private conversation. 

But that one flaw aside, I flew through The Great Hunt & I already have The Dragon Reborn in my backpack ready to start today!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('987b600c-bdd2-47e6-b107-359f2634652e', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'ff6c1210-4274-40fd-889a-50fc37f417c6', 4.0, NULL, NULL, 0, 4, 2025, '2025-04-16T12:00:00.000Z', '2026-03-17 23:30:34', 'I’ve been reading these books so quickly that they’re beginning to run together. 

I appreciated really seeing Mat get to shine with some POVs this time around. 

The ending felt like a true turning point in the series as well. 

I spent most of my time listening to the audiobook on this one, which makes me feel disconnected to the story in a way I don’t like. I can hopefully find more time to sit down with the next one. 

Rankings so far:
1. The Great Hunt
2. The Dragon Reborn*
3. The Eye of the World', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('74bce0f1-494e-4a21-ab08-5ba4d9390dbd', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '42d48717-df0f-49f0-adeb-2597da42f215', 4.0, NULL, NULL, 0, 6, 2025, '2025-06-02T12:00:00.000Z', '2026-03-17 23:30:34', 'Perrin, Man. 

This book very nearly lived up to the hype, which is that it’s one of the greatest fantasy books ever read. 

I struggled to get through the Elayne/Nynaeve/Egwene scenes because I just wanted to see Perrin/Mat/Rand so badly! 

The prose isn’t great, but these characters are so real—frustratingly so at times—that I just want to spend more & more time with them. Everyone has flaws & redeeming qualities that makes them so well-realized. 

I’m going to take a little break from WoT because they’re all running together so far. But I am so excited to be back soon!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('63354b2c-b88d-4438-aa24-aa7d6e92684b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '2360b0aa-b67d-4ae1-92e5-4e3c8d94fb38', 4.0, NULL, NULL, 0, 6, 2025, '2025-06-20T12:00:00.000Z', '2026-03-17 23:30:34', 'I was stuck between four or five stars. I’m going with five for one major reason: the side characters were so good. I actually liked every single character. I’m not sure if I’ve ever been able to say that. 

Weeks didn’t waste any time in showing what kind of book this would be. Dark, gruesome, merciless, exhilarating. Within just the first few chapters, he wrote some of the most horrific acts I’ve ever read in any book. 

There were at least three plot twists that made my jaw drop. Literally. 

The prose wasn’t beautiful & poetic except when it needed to be, which is my personal preference. 

I’m more of an epic guy, so this pacing felt so quick until we got to the climax, then it slowed way down. It wasn’t too jarring for me, but I could see how this would throw some people off. 

Overall, this book may slip into my all time list. I need to chew on it a little longer. In the meantime, I guess I’ll just read the sequel.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('b975dd7f-51ec-4808-8dfb-724cfe158dfa', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd1da0000-680e-4baa-bbef-f8e3b3ab5c07', 4.0, NULL, NULL, 0, 8, 2025, '2025-08-22T12:00:00.000Z', '2026-03-17 23:30:34', 'A satisfying, bittersweet ending to what will go down as one of my favorite series of all time. 

It didn’t contain as many big moments as Shadow’s Edge, but it had my heart pumping as I learned the outcome of some of my favorite characters in all of media (Logan & Vi most of all). 

It wasn’t perfect. The prose was often clunky & the plot connected loosely, but I can overlook those things when I love the characters. And Weeks did that better than I could have hoped. 

After three books in this world, I’m excited to read the prequel & the sequel, so that shows just how-well created it truly is.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('dcccbc83-c811-4986-afa3-cdcba07cab01', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'abb62b81-38d3-402d-9f10-0a6160306ae6', 5.0, NULL, NULL, 0, 8, 2025, '2025-08-06T12:00:00.000Z', '2026-03-17 23:30:34', 'I just read an all-time favorite book for the first time. 

The prose was hit or miss, but that was really my only complaint at all. This story took me through the entire scope of my emotional range. The Christian allegory may have been heavy handed to some, but I found it beautifully moving. 

I genuinely love every character, even the side ones. 

Logan’s arc in this book is one of the best I’ve seen in any form of media. He really stole the show & had nearly every one of the big moments. 

Vi’s arc was a roller coaster & is probably the most enticing thing about starting book 3 later today. 

Brent Weeks is an absolute genius, nearly unrivaled in some of his skillset. At this point, I doubt I take a break through his entire bibliography.

Also, this is how I picture the people complaining about virginity in the books:

https://www.threads.com/@ernest_bigboy/post/DNBVjZRoZ_c?xmt=AQF0y1MrmO90vwMhK-GKsyR_-2-I8hx4ubTEe3jEuAtl5w

It’s like they didn’t read Vi’s arc at all.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e3f57dad-5a50-4012-b4ed-545cfd2fa9c4', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '5ddfa059-5c54-4888-a0d7-565ede82795b', 2.0, NULL, NULL, 0, 3, 2025, '2025-03-08T12:00:00.000Z', '2026-03-17 23:30:34', 'I really don’t have much to say about this one. 

It was a cool idea with an interesting format, but I just could not latch on to any of the characters. They weren’t even fun to hate, just bland. That’s so out of the ordinary for Sanderson, given that he’s written the majority of my favorite characters in all of media. 

I’ll probably forget most of this story in a few months & simply remember it as something that didn’t affect me at all. 

The plot was well-done & the ending was satisfying enough. I just didn’t care enough by that point to feel much.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('44776a90-dba8-47a8-85c3-59425c0e19a1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'c2e27fab-7b8c-4a30-bf29-8750a62918f1', 3.0, NULL, NULL, 0, 3, 2025, '2025-03-05T12:00:00.000Z', '2026-03-17 23:30:35', 'The best definition of a mixed bag I could ever remember. 

I’ve had it on my list to read some RA Salvatore for years. Coming off a long, emotional conclusion to a series, I thought this would be the perfect pallet cleanser. 

And you know what? I was right. 

The prose was a complete mess. The pacing was all over the place. The plot was confusing. The villain was boring. But man, it was fun. And the main cast of characters really gripped you. I have full intention of completing this trilogy in time when I need to go back to a fun, simple read. 

Drizzt, Wulfgar, Bruenor, Regis, & Carrie-Brie would be worth a second visit at least.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('da7d86b8-2be4-4cd7-829e-af58ea00ebfb', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '04ba7da3-114c-4029-8835-ad3abe2051f2', 4.0, NULL, NULL, 0, 2, 2025, '2025-02-06T12:00:00.000Z', '2026-03-17 23:30:35', 'I need to take some time to process this one. 

For the fourth book straight, Adolin Kholin stole the show for me. 

I was honestly worried through the first half of this book. A lot of things felt off to me. The therapy talk was really corny. A few characters—Kaladin & Szeth for example—felt as though their voices had completely changed. There were so many callbacks to scenes in previous books that it seemed this book wasn’t even trying to stand on its own. 

But the ending. Oh, the ending. The redemption. The sacrifice. The growth. 

Not a single character ended up where I thought they be or even completely where I had hoped, as is life. 

Four years of online theories & I never saw any of them come to fruition, but I was satisfied. It made sense. That is where this story was heading this entire time. 

I love these characters. I’ve spent so much time with them. I am genuinely mourning them & I’ll think so much over the next few week—perhaps months or even years—about their stories. 

I’ll need to re-visit Roshar soon, to get to know my friends all over again. In the meantime, I may take a little break from reading to let this one settle. 

After all, journey before destination, right?', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('ba2e5fb4-67b1-48ee-939c-eb2542ab5621', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a012d7db-2bc7-4fd0-ab47-71574dd310bb', 4.0, NULL, NULL, 0, 12, 2024, '2024-12-12T12:00:00.000Z', '2026-03-17 23:30:37', 'Bast was by far my least favorite character in The Kingkiller Chronicles, so I was surprised by how much I enjoyed this novella. 

It was enjoyable to get a bigger glimpse into the world of the interludes & see what life was like in the town surrounding the Waystone Inn. 

I don’t have much to say on the matter. The prose contained its typical beauty, the banter was humorous, & there were some heartstrings being played by the end. 

I can now impatiently await book three with everyone else!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2db3512f-bd27-493a-91b9-965ef16ce714', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '3e121687-0ddf-4a52-8d1a-e0257354ce0e', 3.0, NULL, NULL, 0, 12, 2024, '2024-12-11T12:00:00.000Z', '2026-03-17 23:30:37', 'This book was objectively good, but it was a struggle for me. 

Auri such a fun character to view through Kvothe’s eyes, but 150 pages from her perspective was exhausting, as much as I hate to say it. 

The prose was wonderful & I enjoyed it more when I switched to audiobook. 

If you love The Kingkiller Chronicle, this one is worth your time. If you’re a casual fan, maybe not.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('1f7dadf8-8721-4a98-bb40-d3fbb7cb6503', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '75a10606-d526-40b5-8789-e883f9c798c8', 4.0, NULL, NULL, 0, 12, 2024, '2024-12-10T12:00:00.000Z', '2026-03-17 23:30:38', 'My absolute favorite kind of book is a slow building fantasy epic. That being said, this one could probably trim off 300 pages. 

I feel so attached to these characters, especially Kvothe, but there were a few sections—one in particular—that was a real slog. 

That the only thing that keeps this from being a five star book for me. 

The magic system is wonderfully intricate. The world building is top notch. The prose is some of the best in the history of literature. 

The best part about a slow build is that the resolution will typically knock your socks off. This book & its predecessor didn’t do that. I’m assuming the reason is that the third book will satisfy that need for me. Since it’s all one big story, I have no issue with that at all. I look forward to hopefully experiencing that climax one day! 

However, if The Doors of Stone never gets released, I’m satisfied with the enjoyment I’ve gotten from Rothfuss’ world. It feels like I’m getting to experience a modern fairy tale & that makes the journey that much more enjoyable.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('c1a181d2-f4f5-490f-8e08-87a01732e192', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '50673ab1-52c8-4a80-aa92-716679583d3c', 5.0, NULL, NULL, 0, 12, 2020, '2020-12-17T12:00:00.000Z', '2026-03-17 23:30:40', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('30cf3e94-3e01-44cc-b162-5b9163e3a159', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '426c44db-165d-436f-91e0-6b7732120a25', 5.0, NULL, NULL, 0, 7, 2019, '2019-07-07T12:00:00.000Z', '2026-03-17 23:30:45', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('18466e25-e41a-43e4-8cff-eaaf58a9c9b4', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '420ef077-ac79-484f-842f-e8f513ae1642', 4.0, NULL, NULL, 0, 6, 2024, '2024-06-12T12:00:00.000Z', '2026-03-17 23:30:48', 'This book had some nostalgia for me. I first discovered Comer by seeing him speak at Catalyst Leadership Conference in Atlanta in 2018, where he spoke on this very subject in what felt like the infancy of what would become Practicing the Way, both the book & the organization. Since then, he has become one of the most influential secondary voices in my life. 

Would this book be considered his masterpiece? No. The Ruthless Elimination of Hurry & God Has a Name both still exist. 

Comer has a writing style that I’ve always really appreciated. He has an ability to take really complex topics & content, then package them in a really accessible way. He has an extraordinary gift of teaching/preaching that is a breath of fresh air. An incredibly intelligent man that feels no need to prove that fact to anyway. It’s hard to find both of those qualities in the modern western church. 

So given the sermons & podcasts I’ve already consumed from Comer, I didn’t find much new information in the book, but the organization of it all into one place did feel fresh. 

Comer has a way of bringing quotes from other ministers that are always just poignant enough to really drive his points home. 

The practical steps reinvigorated my heart for a disciplined life & to learn to live the lifestyle of Jesus. 

I’ll chew on this one for the next few weeks & try to take account of my soul. 

This book was a nice little pallet cleanse after four straight Tolkien novels. I’m thankful for this book.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('8fd32448-c1ab-4786-8639-7344f6cbf1e3', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '6850a9ad-d513-438a-aa33-49b4ae3946d4', 4.0, NULL, NULL, 0, 6, 2024, '2024-06-07T12:00:00.000Z', '2026-03-17 23:30:48', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e35099b0-4346-415f-8ed9-790bcf9bb006', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '6042f0ed-0ac5-419c-a8eb-8da45b3e83ee', 4.0, NULL, NULL, 0, 6, 2024, '2024-06-03T12:00:00.000Z', '2026-03-17 23:30:48', 'This is definitely the book from which the movies diverged the most. 

It was nice to see more of the story after the war ended, with the Hobbits going back to the shire for multiple chapters. It felt a little jarring as far as pace and stakes are concerned, but I enjoyed that extra time with them. 

Now that the story is concluded, I found that the characters of the Hobbits & Gandalf were brilliantly done, but it felt as though Legolas, Gimli, & Aragorn were pretty one dimensional. 

Without getting into spoilers, I also appreciated seeing the end to some of these characters that weren’t shown in the movies. 

Overall, I’m very glad I finally marked this trilogy off my TBR. I really loved these books overall & it’s an experience everyone should have in their lifetimes.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('31be34e4-f82c-4eff-a302-0789c3d676cb', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '06648fea-70a1-4bc3-945b-1af7f3e071c6', 4.0, NULL, NULL, 0, 5, 2024, '2024-05-31T12:00:00.000Z', '2026-03-17 23:30:48', 'I’m not sure this review will look much different from my review of The Fellowship of the Ring. 

Rob Inglis nailed it again. I was really interested to see how he would perform Gollum and I really loved it. This was recorded before the Peter Jackson films, so I was curious how similar it would be to Andy Serkis’ performance. 

The plot points don’t hit exactly the same as the movie, so I found myself extremely invested and on the edge of my seat. 

Sam is still my favorite character, just for the record. 

Gimli’s & Legolas’ friendship is almost as endearing as the movie’s interpretation. 

Onto book 3!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('35c9d6e9-97a1-4a72-8528-0b6f66fc2d9b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '73bb5357-0067-4d84-8075-bba6f289cebf', 4.0, NULL, NULL, 0, 5, 2024, '2024-05-27T12:00:00.000Z', '2026-03-17 23:30:48', 'I have seen the movies many times & I have finally gotten myself to start reading the books. 

I’ve always heard that it takes a while to get used to Tolkien’s prose. That wasn’t the case for me. There are definitely some patches that are very dry (I’m looking at you, Council of Elrond), but I actually found this a relatively easy read. The memories of the movies may have helped the characters come to life, but that doesn’t take away from how richly Tolkien penned them. 

It is definitely a victim of the faults of classic fantasy, but it doesn’t lose a star for that. We wouldn’t have modern fantasy without the original one. I can deal with the overreaction of settings & the characters telling flashbacks in their own voices. It just helps me appreciate the new guys from a different perspective. 

Things then first time I’ve ever paired a book with the audiobook, since I’m trying to finish it by a certain time. Rob Inglis’ narration was absolutely brilliant & actually helped me pay attention, something that has always been a struggle for me with audiobooks. 

Tom Bombadil was also way too fun of a character to have been cut from the movies. 

I’ve already started The Two Towers. Despite knowing the story, I found myself on the edge of my seat through The Fellowship of the Ring & immediately jumped into the next book.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('4beca9f7-176e-4a7d-bf5f-1c463b221e9f', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'f97c8e03-6fed-4348-a8ed-fddbaffd7cc3', 3.0, NULL, NULL, 0, 4, 2024, '2024-04-29T12:00:00.000Z', '2026-03-17 23:30:55', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('c603f87d-dd23-4576-96a4-8d33fa9423b9', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '5491930f-9967-4f0a-838b-b72da29adee1', 4.0, NULL, NULL, 0, 2, 2024, '2024-02-19T12:00:00.000Z', '2026-03-17 23:31:03', 'Does Red Seas compare to its predecessor? Yes, despite not quite living up. 

Mission: Impossible meets Ocean’s 11 meets Black Sails if it was directed by David Fincher. 

It had been a few months since I’d read The Lies of Locke Lamora. And despite that, the first few chapters of this entry still had me on the edge of my seat as the consequences from their first adventure started to be realized. My heart was beating just as quickly as if it were happening to me. 

There was a definite slog in the middle of this book that I powered through as they learned what they needed to know for their mission. But once they set sail, I was back in! 

The ending may not be as classic as the first book, but I think it did live up to the IP. 

The biggest downgrade from Lies was definitely the flashbacks for me. I was having trouble differentiating between that & the present. It felt forced to just match the organization of the first book. I would’ve preferred to just read the flashbacks & then immediately go Into the current story. 

The real strength of this book was the same as Lies: the characters & their relationships with one another. When something happened to one of them, Lynch was brilliant in making me feel the event through the eyes of someone I truly believed loved them. That’s hard to do & he is one of the best in the genre at that. I’ll be ready to read Republic of Thieves just a few books into my TBR!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f36ff16d-ce89-4807-a7cf-f244bcf84235', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '15f9b827-07c9-42f5-ab7d-f5bcdea91b05', 4.0, NULL, NULL, 0, 12, 2023, '2023-12-02T12:00:00.000Z', '2026-03-17 23:31:03', 'Freaky Friday meets Lost in Translation meets Studio Ghibli. 

The worldbuilding was very Sanderlike. However, I found myself intrigued with Painter’s world far more than Yumi’s. The imagery of the pink & blue neon painted the picture (pun intended) in my head brilliantly. And the typical Sanderlanche had me enthralled in the last 80 pages! 

Sanderson does a fantastic job of building side characters that almost overshadow the main characters (Mistborn & Stormlight especially), but this was a book that focused solely on the two leads’ inward journeys. The development & the romance both felt so natural that these characters became real to me. 

The magic system wasn’t the focus, but it moved the plot along & was interesting enough. It’s a world I’d love to visit again, but I’m also satisfied with just this one story. 

Hoid’s narration didn’t feel as Hoid-like as it did in Tress. Not a complaint. Just an observation. 

Overall, I’d say Tress was a better book, but I personally enjoyed Yumi & the Nightmare Painter more. I’ll be moving on to The Sunlit Man next!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f4293f19-ee1d-4884-a98a-0e5ce5dde8f4', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'be963910-85f0-48eb-a2fc-3eeea337328d', 5.0, NULL, NULL, 0, 11, 2019, '2019-11-29T12:00:00.000Z', '2026-03-17 23:31:12', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('3151aeff-6bc4-4f20-8a23-f4d6dddc4028', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a21fcd9e-3d06-47d0-809f-bac86d255e19', 2.0, NULL, NULL, 0, 9, 2023, '2023-09-20T12:00:00.000Z', '2026-03-17 23:31:17', 'I’m going to be honest. I did not like this book. 

Paolini had some beautiful prose as always & I did find myself intrigued by the mystery, but I just hated every character to a degree that I had nothing on which to latch. 

This book was less than 300 pages & it took me over a month to read it. I ended up having to switch to the audiobook (which I’ve never had to do before) because it was such a slog. I really hate audiobooks too. 

I’ve been on such a great streak of books the past year or so that my standards have been pretty high, so maybe this is just me. Overall, I’ll give it a 2 because it was a technically good book. I just dreaded picking it up.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e330ab67-9778-4960-a3b4-2035c3e26d7f', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd099d1de-7993-455a-918b-b8ae10e50058', 4.0, NULL, NULL, 0, 8, 2023, '2023-08-12T12:00:00.000Z', '2026-03-17 23:31:37', 'I had some very mixed feelings about this book as I read it. 

Honestly, if you can get through the inception of an intro, it’s pretty much smooth sailing from there. The book within a book aspect definitely worked better in the movie. 

What worked better in the book, however, were the characters. I actually felt like I knew them by the end. While the movie was fun, humorous, & just better to be honest, I felt that I actually knew the characters much better by the end of the book. 

The style felt like a cross between Narnia & Monty Python, which is the highest of compliments. 

I would recommend this to anyone that likes fairy tales, fantasy, or classics. It’s just one of those books that everyone needs to read at some point.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('fdfef552-d31b-49e2-9e92-94bae30a1b11', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '8cec0d8e-e612-412d-8dac-89512b4c61f2', 5.0, NULL, NULL, 0, 8, 2023, '2023-08-05T12:00:00.000Z', '2026-03-17 23:31:37', 'I’ve heard rave reviews about The Gentleman Bastard Sequence for years. Having given up on Scott Lynch ever finishing the series, I decided to just pick it up now. 

Having spent the last year reading the entirety of Brandon Sanderson’s Cosmere universe, I was pretty accustomed to his writing style, so Lynch’s prose was pretty jarring for me. I did get used to it & it definitely fit the overall ambiance of the novel, but I can’t say I loved it. 

I actually spent the first quarter of the book trying to figure out what all the fuss was about. It didn’t seem to be anything special and, if I’m being honest, it seemed pretty pretentious & like it was trying too hard to be edgy. 

But at some point (and I’m not really sure what point it was), it just clicked. I really just fell in love with this book & every protagonist in it. I had to get in the habit of dropping my jaw every hundred pages or so. 

It could possibly have my favorite antagonist I’ve ever read before as well. Whenever our “heroes” were in the presence of either the BBEG or his hireling, I felt real danger & was prepared to witness a death. The gruesomeness led to realness for me. 

For most of the book, I couldn’t decide if I preferred the flashbacks or the main story. By the end, however, I felt like the flashbacks should’ve been finished in part 3. They felt very much in the way of the pacing in the final act, despite some very helpful worldbuilding. 

It honestly didn’t feel like fantasy with the minimal use of magic, but it did in the worldbuilding. Camorr felt so real to me that I would swear to you I’ve spent the last month living there. 

In conclusion, The Lies of Locke Lamora isn’t without flaws, but it’s the easiest five star read for me since Words of Radiance. I plan to jump into boom two very soon!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('936966aa-c124-4ed6-b793-8875b1c7a5ca', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '50e91b4b-17f8-4bf5-af6b-cb31962e334b', 4.0, NULL, NULL, 0, 6, 2023, '2023-06-24T12:00:00.000Z', '2026-03-17 23:31:37', 'The best way I can find to describe this book would be charming.

It felt like I was reading a fairytale but not quite. 

I could definitely see the Princess Bride inspiration, but I actually feel that it scratched my Narnia itch that is very seldom satisfied. It reminded me so much of the Silver Chair.

As per usual, Sanderson’s worldbuilding is top notch. The idea of oceans with spores that react dangerously to water is so utterly brilliant that I wish I’d come up with it! 

The characters were all quite three dimensional & oh so endearing. 

But I think my favorite parts were the twists thrown into such a simple plot. I won’t spoil them here, but they honestly made the book for me. 

Was it as incredible as a Stormlight or Mistborn book? No. But it was exactly what it needed to be in the best way.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2abb3e41-33f1-4bc4-a3a6-55a4ec47909e', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'b24d07de-06e1-4bd3-89dd-07240e8ee1b3', 4.0, NULL, NULL, 0, 6, 2022, '2022-06-26T12:00:00.000Z', '2026-03-17 23:31:41', 'I actually took a Physics class from Dr. Hedin the semester after his Boundaries of Science class had been shut down. I was unaware of the scandal at the time. But after running into him at a revival meeting during the semester, I was completely confounded with the idea of a man working in the science department of the most liberal school in the state (a quite conservative one, I admit). 

I’ve told that story to a few people over the nearly nine years since it happened. But recently, someone responded with this book recommendation, knowing exactly about whom I was speaking. So I ordered it on a whim. And I was not disappointed. 

I’ve been a subscriber to Astronomy magazine for years now. I love the idea of discoveries in astrophysics. But I’m also a youth pastor that loves the idea of making sense of theology. This book would be a recommendation for anyone with even the slightest interest in apologetics. 

He went over topics about which I’ve had many conversations, but he also touched on subjects about which I knew nothing. I was intrigued throughout the entire book. Personally, I believe the true strength of it is in the first & last chapters. Professor Hedin had a wonderful way of telling the story of his rollercoaster responses to his class. His skill as a teacher (that I know from first hand experience) was on display as he took complicated subject matter & translated it into terminology that help it make sense to people on most levels of intelligence & education. 

Bottom line: I was encouraged & educated. God is moving in the scientific community. It was wonderful to see the details of how.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('d3aef2d2-7dfe-416a-97a2-edd988e79b7a', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'c734d0d8-1f9e-4b77-b9bb-5f283324e47d', 4.0, NULL, NULL, 0, 6, 2023, '2023-06-10T12:00:00.000Z', '2026-03-17 23:31:41', '[SPOILER]
This is definitely my least favorite entry in The Stormlight Archive. But it’s still Stormlight, so it’s a four star book. 

It took me four months to read it. It turns out that reading four straight 350,000 word books in a series is pretty taxing. Especially when you move states in the middle of it. 

I’m not a huge fan of the Die Hard storyline. And I really just do not care about any of the Parshendi characters at all. 

However, there were so many things I loved in this book: Kaladin’s arc, getting to see Navani shine on her own, & the deepper dive into Spren cultures. 

I would’ve liked to get more time with Shallan & Adolin. I personally thought that was the most intriguing story in this book & I felt that the lack of exploration made the end of it feel a little like a deus ex machina. 

Overall, I’m very satisfied with Rhythm of War & I enjoyed another book of hanging out with one of my favorite casts of characters ever written. I’ll be reading book 5 on release day!
[/SPOILER]', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e0a4946e-5274-4f74-9eae-b1b8375420e2', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'f4623793-0fb8-46da-8070-5da09e9bdb5a', 5.0, NULL, NULL, 0, 11, 2018, '2018-11-10T12:00:00.000Z', '2026-03-17 23:31:46', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('b68ed699-fe6f-4694-922d-2cf552816904', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '9cdae90a-23e5-47d2-965d-1cb315fc617c', 5.0, NULL, NULL, 0, 2, 2023, '2023-02-11T12:00:00.000Z', '2026-03-17 23:31:46', '[SPOILER]
Oddly enough, this book really did feel like the finale of a trilogy. I’m not sure what direction they’ll take it from here, but I’m very excited. 

Oathbringer was definitely not as close to perfect as the first to installments of the series, but it was still much closer than most books. 

I would call this the worldbuilding book in The Stormlight Archive. Experiencing Shadesmar firsthand was riveting. Getting to see Kaladin, Shallan, & Adolin be a trio for most of a book was something I really wanted. 

The history & culture that Sanderson has built is nothing short of incredible. 

And as a fan of redemption arcs, I’m so excited for where Szeth’s story may be going. He’s one of the most interesting characters I’ve seen in a long, long time. And his interactions with Lift were very entertaining! 

And speaking of Szeth, It was so exciting to see the Cosmere overlap a little bit in this one! 

I’m immediately picking up Dawnshard & moving right along in my Stormlight journey!
[/SPOILER]', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('9e210852-d7f8-41cc-9e32-7e463644fef6', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '8b18529a-c6c5-417a-8e63-a1ff19d1ec94', 4.0, NULL, NULL, 0, 12, 2022, '2022-12-15T12:00:00.000Z', '2026-03-17 23:31:53', 'Wow. I did not expect that ending. 

Eight years of these characters is all over. It started reading it from the very beginning. It’s kind of hard to wrap my head around. But I’d say I feel satisfied. It was heartbreaking, but it was also perfect. That’s really how I would explain the entire series. 

I won’t say spoilers, but it was nice to see happy endings for at least some of the characters. 

I’m glad I reread the entire series to have it all fresh in my mind. It’s something that will be on my mind for a while. 

I’ll need to read Kaya to get my fix of Wes Craig’s art now.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('ea60d351-15f4-46a7-bf4d-4df9142fea7a', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '03153b98-14a6-4d38-90da-0b1dd5b14a3a', 4.0, NULL, NULL, 0, 12, 2022, '2022-12-15T12:00:00.000Z', '2026-03-17 23:31:57', 'One thing I’ve always loved about Deadly Class is that it makes me sad in a good way. This volume definitely made me sad, but it was almost more regretful. 

I appreciate knowing that any character could die at anytime. And I love seeing these characters almost 20 years later, but the realism of it, while beautiful, is also hard to read. 

All that ti say, Remender built this up perfectly & succeeded in everything he intended to do. As I enter into the beginning of the end, I truly have no idea what could happen. 

And Wes Craig is still brilliant. The little process sections in the back of the book are so interesting to look through!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('d5f03006-288a-4fb3-a2d6-5a612f7638b1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '386cba6f-f2e1-4701-8d8c-1e11e6a14fd4', 4.0, NULL, NULL, 0, 11, 2021, '2021-11-24T12:00:00.000Z', '2026-03-17 23:32:00', 'My all time favorite series, writer, & top two favorite artist, so I’m a little biased. 

The penultimate volume of the series is made to set up the finale &, oh boy, does it do just that! 

I haven’t been that fond of be new class of student d as compared to the likes of Billy, Willie, & co. But this volume finally pulled me in on that. 

I always have a lot of confusion because of the months j take between volumes, but Deadly Class somehow always catches me up & delivers. 

Reminder delivery is usual teen angst in all its unedited, brash goodness! 

Craig has grown into one of my favorite artists. The way the panels can give me the feel of a scene & have me emotionally in the room with them is a true testament to the artform. 

And Loughridge shows why the colorist is the cinematographer of comics. Boyd was great, but Loughridge’s work on this series continues being elite. 

This volume has properly prepared me for the final arc. I plan to reread the entire series going into it, just to make sure the emotional impact is accurate!

Edit for second reading:

Having read the entire series in just a couple days in preparation to read the finale, I do understand this story much better with it fresh in my mind. 

The timejumps were jarring, but a part of my has always liked that little trick. Seeing where someone ended up without having seen the progression has so much potential in a story. It looks to me like the final arc is going to live up to the hype built up by the series so far!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('80390f63-bcf0-4201-9bf2-5d45b481b415', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e4981de5-e355-4fa2-a69e-345a03916d93', 4.0, NULL, NULL, 0, 7, 2020, '2020-07-08T12:00:00.000Z', '2026-03-17 23:32:03', 'My first Deadly Class review under five stars. Indefinitely didn’t hate it. It was just more chaotic and hard to follow. A few of them went out of character from what I could see. It had a few moments that really jump out at me, especially in issue 44. 

Uncertainly enjoyed this volume more than the first time I read it & had forgotten everything that had happened in the volume prior. I’m still excited to continue on with the last 12 issues & see how everything plays out! 

And as always, Wes Craig, man. Drawing this well should be illegal!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('29189757-0421-4889-b942-123e311af7f3', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'b4897286-f902-4df9-96c1-9bc229c85893', 5.0, NULL, NULL, 0, 8, 2019, '2019-08-13T12:00:00.000Z', '2026-03-17 23:32:05', 'I’m really feeling like I’m inching toward the end now. Remender has done a phenomenal job of bringing this story full circle. Our main characters going back to the titular setting with a supporting cast of new & old characters feels fresh & familiar all at once. I especially love the hallucination scenes.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('8c693c13-faf5-452e-b285-b879eb3d562a', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'aa31bf93-53da-4a65-a7b8-4f57a7b3f961', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-13T12:00:00.000Z', '2026-03-17 23:32:07', 'Man, I would’ve loved to have seen this arc play out with the cast of the show. It had been so long since I’d read this one that I’d actually forgotten a few of the bigger plot points & I could not remember what had happened. Other than four characters, I could not remember who survived. That made it pretty hard to put down. 

Remember really knows how to make you love characters, fear for their lives, be shocked by what happens, & be annoyed at yourself for not seeing it coming because it makes perfect sense. It reminds me of why I fell in love with his writing during his Dimension Z arc on Captain America. 

And obviously, Wes Craig again!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('0f2584cd-6410-4e35-ac72-9de778768376', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '582ece14-75a4-4f9a-8075-5f75cc55e9b8', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-13T12:00:00.000Z', '2026-03-17 23:32:09', 'I would say this is the strongest entry of the series on the second time through. The new class of freshmen have mostly grown on me, especially Zenzele & Helmut. It felt like it had taken a little break from the original feel of the comic but is back with this one. 

The story was intriguing. So many twists & turns that it really didn’t see coming. 

This volume had some of my favorite spreads in the series. It’s almost like Wes Craig is getting even better!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f9977ef3-3ad6-45cc-9d3c-dc40d5f12ba1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '8e294d96-9ef4-45cc-97ea-06f6a0188104', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-13T12:00:00.000Z', '2026-03-17 23:32:11', 'This definitely isn’t my favorite arc in Deadly Class. The new freshmen were definitely less jarring than the first time I read it, but there’s something about the old group that I’ll always miss when I reach this point. 

The reason this wasn’t a four star is because of issue 26. It’s in the running for my favorite issue of the entire series. 

Also, I’m running out of compliments to pay Wes Craig. He’s just so good.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e7488901-e8c7-4d01-a862-2439ab59aef1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '980cb4d0-7409-4d7d-be21-87df61a5fe2b', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-13T12:00:00.000Z', '2026-03-17 23:32:13', 'Volume four is the real heart of this story. Most of the parts of Deadly Class that I’ve spent time thinking about over the years is in this volume. 

The stakes have always felt real, but going into sophomore year in volume five with only one of the main cast was not expected the first time I read it. 

I’m excited to jump straight into the next cast for volume five & see if I view them differently this time around.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('55ade07e-5dbc-4b58-93e2-f796caacbbe4', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '54f54247-54c3-4dd0-8538-1e403b88cbf2', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-12T12:00:00.000Z', '2026-03-17 23:32:15', 'A solid entry. A connecting arc between two of the more memorable ones. A lot of drama & misunderstandings setting up the hunt of the rats. The mystery of the Maria set up but yet to be explored. I’ve forgotten just how much I loved this series & why it’s my favorite comic ever written. Despite it being a reread, it’s still quite the page turner for me. 

And Wes Craig is still one of the best in the game after three straight volumes.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('0939b157-e636-483d-87a5-fec7aa0a0d5e', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'bcb694e7-10a0-445f-9d07-7b96889c33c1', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-12T12:00:00.000Z', '2026-03-17 23:32:17', 'Volume one was a fantastic introduction & now we finally get to dove into these characters. I’ve always been impressed by Remender & Craig for their ability to use the magnifying glass of a school for assassins to really show who the kids are: very broken with the inability to trust anyone. 

The backstories for Marcus & Maria gave some great depth. I remembered both stories well from my first read in 2014/2015, but it was still so enjoyable. 

And also, Wes Craig is a madman. One of my favorite artists of all time. Some of these page layouts seriously blow my mind.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('fbb90876-8105-4228-bf9a-278dbc07c577', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e2fc1974-1c0b-4588-af79-8e01d089d987', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-12T12:00:00.000Z', '2026-03-17 23:32:19', 'Im rereading the whole series leading up to finally reading the final volume, so this is my first time rereading this since it was first released. The difference in perspective as a 28 year old compared to a 20 year old is vast. 

Some of the memorable lines from Marcus & co have become a little more cheesy, but not necessarily in a bad way. It feels authentic for a teenager. While it may not be relatable to my current self, I still feel myself remembering those times. 

This is one of my favorite ensemble stories of all time. And since some of this main cast isn’t around anymore, it was so nice to visit them again. With this being my first read of volume one since the syfy show aired, I now read it in the actors’ voices & am able to compare scenes. It’s clear to me that the show was able to expand on some of the best parts of this comic. It didn’t necessarily do them better, just more completely. For instance, the friendship that blooms between Marcus & Willie was far more natural in the show. But 45 minutes is easier to work with than 22 pages.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('2b7ad8f8-f1db-4ab7-88ba-d52026bc0305', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e56c6e38-96f4-4010-98d5-dec478e7e735', 5.0, NULL, NULL, 0, 12, 2022, '2022-12-08T12:00:00.000Z', '2026-03-17 23:32:19', 'Brandon Sanderson answered the question of how to top The Way of Kings. 

He somehow made me love the characters I hated (Dalinar & Adolin) while making me love the characters I liked (Kaladin & Shallan) even more. 

I’ve never had quite this emotional response to a book. My adrenaline was pumping during the entire last 500 pages. I was fully invested in every storyline, wondering about things I thought couldn’t have been over, and trying to figure out where on earth it could all go from here. 

The book-long buildup of characters made the culmination so satisfying. Seeing our main characters finally cross paths & form relationships with one another made it seem that two of my friends became friends with each other. Seeing the roller coaster of character arcs go up & down for 1200 pages to finally blow me away at the end was worth the month & a half I spent reading it. (It was the holidays! Life got busy!) 

I will leave my review a 5/5 until Goodreads allows me to give a higher score.

PS Rysn’s interlude was great & I’m pretty stoked for Dawnshard!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('f5d753ab-0835-4d5e-bec5-c3c2d399c985', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'def400ae-2640-4bea-b0bc-3a4e47743c41', 4.0, NULL, NULL, 0, 12, 2022, '2022-12-11T12:00:00.000Z', '2026-03-17 23:32:21', 'It’s always nice to read a collection of short stories. Nine Stories by JD Salinger is one of my favorite books of all time. 

I took a big break before Edgedancer to read Way of Kings & Words of Radiance. Considering those are two of the most highly praised fiction books ever written, it was hard to sandwich this in there.

It almost felt like the interludes in the Stormlight Archive. Hit or miss with me really just wanting to get back to the main story despite enjoying them quite a bit for the most part. 

Emperor’s Soul was good. Started out slow, but I really enjoyed the characters. 

Hope of Elantris was okay. It was nice to fill in the little bit from the book. 

11th Metal was pretty good. More Kelsier is always nice. 

Allomancer Jak was deliciously pulpy & so fun to read. I laughed out loud multiple times. 

Secret History was good. Slow at times, but I was really emotional by the end. 

I much preferred the written form of White Sand to the comic form. 

Shadows for Silence in the Forests of Hell is my favorite by far. Great character work, worldbuilding, & mystery! The stakes felt so real for only being 50 pages! 

Sixth of the Dusk was my second favorite. Intriguing character work & cultures along with a story that kept me on the edge of my seat. 

I enjoyed Edgedancer more than most people seem to. But I also enjoy Lift more than most people seem to as well. So I guess that makes sense. 

I do feel like an official Cosmere fan now, so that’s nice!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('bf09e658-4ca6-4a0d-b06b-f23c351bb04b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a6f643eb-edd9-4f23-96ab-b984297556b0', 5.0, NULL, NULL, 0, 10, 2022, '2022-10-21T12:00:00.000Z', '2026-03-17 23:32:21', 'This felt like the longest setup I’ve ever read in my entire life. And it was perfect in every way. 

I’ve read the entire Cosmere building up to The Stormlight Archive. This is truly Sanderson’s magnum opus! 

It’s long. It’s dense. But it pays off so well in the end. 

This is a spoiler free review, so I’m not going to get I to any story. I’ll just say that I absolutely adored the chapters that followed Kaladin & Shallan/Jasnah. I wasn’t as fond of the Dalinar/Adolin story, but I definitely didn’t hate it by any means. 

The entire buildup of all of these separate storylines made the last 100 pages of this book about as exhilarating as it gets! 

I’ll need to chew on it, but this may be the (objectively) best book I’ve ever read.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('eabff769-2ded-45ea-b056-89c4bef2d113', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'c293dda5-2398-4ec5-a874-ba7e83036054', 4.0, NULL, NULL, 0, 9, 2022, '2022-09-29T12:00:00.000Z', '2026-03-17 23:32:22', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('b3768f19-e176-4ee4-b87d-560e1caf012b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '6e392609-cfcb-40dd-8a20-0677999ecc68', 5.0, NULL, NULL, 0, 9, 2022, '2022-09-11T12:00:00.000Z', '2026-03-17 23:32:24', 'The five stars is not because this book was an easy read. As much as I love Lewis, his nonfiction books can ramble a bit. And the old English prose is rough at points; three page paragraphs & full paragraph sentences are no longer the accepted style. 

That being said, I was enthralled by the story. Arguably the greatest theological mind of the 20th century telling the story of how he came into the faith. How could you not love it?! 

The facetious banter was top notch. Some great lines came out of this read! 

“God is, if I may say it, very unscrupulous.” 

He’ll go to extreme lengths to use us to reach others. And very few have reached a fraction of the amount reached by CS Lewis. And it was an origin story to fit the man.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('e1d20e05-d438-4d71-aa5e-f3c3f1630ec9', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd02cb82e-5697-4ba6-b89c-b3b0417da35e', 5.0, NULL, NULL, 0, 8, 2022, '2022-08-31T12:00:00.000Z', '2026-03-17 23:32:24', 'This book followed a similar path to the second entry of era 1, The Well of Ascension. Although, in my opinion, this was more impressive. I don’t mean that it’s a better book apples to apples, but more of an improvement as a follow up to their predecessors. (Granted, this one did have much less competition.) 

Mystery, mistrust, & twists. Brandon Sanderson once again follows every step for a perfect crime thriller set in a steampunk fantasy world. With even more callbacks to the original books (but still not enough to be overkill), I had a hard time putting this one down! Every chapter gave new revelation that begged me to keep reading. 

A definite improvement over its predecessor, it took the more lighthearted & fun character-driven story & gave it a real gut punch that just felt necessary. I definitely recommend this book, but prepare your heart for it.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('cf8b8e2b-283c-45cb-98ff-3f1fb674fe37', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'a86d43c6-7b07-4379-859c-5d3f5f4f5654', 4.0, NULL, NULL, 0, 8, 2022, '2022-08-16T12:00:00.000Z', '2026-03-17 23:32:24', 'Why shouldn’t I have read this first again? 

I must say, I absolutely adored this book. 

It was really three stories, overlapping slightly here & there, that come together at the end. Two of these stories (Raoden & Sarene), had me riveted. The third (Hrathen) was a bit of a chore to get through in the best way possible; I hated a character I was meant to hate. 

Without giving away any spoilers, I’ll just say that the characterization & worldbuilding, while not as polished as his later books, we’re textbook Sanderson & I found myself feeling like I was really a citizen of this world & a friend of these characters. The ending felt like a machine gun with all the twists in the last few chapters. I count at least five in hindsight. The mystery that kept my attention for 550 pages paid off for me in every way. 

And there were still enough unanswered questions to have me stoked for this sequel that’s apparently being written! 

If you’re a big Sanderson fan or just a lover of fantasy in general, I suggest giving this one a try!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('85578d19-a4d6-4eb9-b081-e1b1fdb87125', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '8706913a-cc7c-4511-a1db-59066f64f164', 4.0, NULL, NULL, 0, 8, 2022, '2022-08-19T12:00:00.000Z', '2026-03-17 23:32:25', 'Another classic CS Lewis book! 

The people I hear disliking Lewis’ fiction work seem to be misunderstanding what he is. He wasn’t a fiction writer sprinkling in theology. He was a theologian using fiction as a parable to help other understand his point. The Chronicles of Narnia & The Great Divorce show this  well also. 

Whenever I read Lewis’ 80 year old works, I realize some of these “modern” issues in Christianity aren’t as modern as we may think. Postmodernism was a problem in 1940s England just as much as in 2020s America.

He does such a good job of giving us a perspective we very seldom think about: demons. How they root & cheer for things that most of us think are no big deal, how they try to find the easiest ways to convince us to pursue our own pleasures, how they interact with one another in an effort to get us to slip. 

Of course most of this is speculative fiction, but it does make a lot of since in the most interesting ways. And, as Lewis often does, makes me think about my own relationships with others, Jesus, & even the demons themselves.

I’m glad to finally have this one marked off my list so I can think about it for a very long time.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('a1114861-d4c3-438f-bb20-1e804ee8105f', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '8d8b4176-e183-4f0c-b408-d590b1341de7', 5.0, NULL, NULL, 0, 1, 2022, '2022-01-04T12:00:00.000Z', '2026-03-17 23:32:27', 'Wow. 

It’s been so long since I read a book that I didn’t want to put down. 

It was so refreshing. The worldbuilding. The magic system. But most of all, the characters. 

Sanderson was writing with a paintbrush here. These characters completely came to life. He took character tropes & put twists on them that made it seem so fresh. The hardened master? The street urchin turned protagonist? The aristocratic love interest? The evil warlord? None of them quite fit into their molds. 

Maybe this is weird for a guy, but as much as I loved the action, the allowance, the political intrigue, I have to say my favorite part by far was the romance! It actually had me on the edge of my seat. I truly believe the scenes at the ball were the most cleverly written sections & I was always itching to get to the next one. 

I understood why every character did what they did, whether I agreed with the action or not. They made me laugh, they broke my heart, they frustrated me, all in the best ways. 

I’m so happy to have been this attached to a group of characters & I’ll be picking up the next book first thing tomorrow morning (since I need to go to sleep right now)!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('5cfe587a-5007-45a2-bc6b-596f15f6dd0b', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'e4292c3b-4377-4ab4-8363-5eb928ea310f', 3.0, NULL, NULL, 0, 8, 2022, '2022-08-05T12:00:00.000Z', '2026-03-17 23:32:29', 'I didn’t dislike this read at all. It just kind of felt like nothing happened. 

It was nice to see that Toph’s character felt congruent with the television series. She would totally hate teaching at a bending academy! But it doesn’t really feel like that is ever resolved. Her three original students returning was nice. They were some fun characters in The Rift. 

The art & coloring were up to par with all the other stories & the dialogue continued being great. These books just feel like a money grab to get people to buy anything with the ATLA logo on them. The writer, artist? & entire team definitely have some heart behind it & they’re doing a great job, they just aren’t doing much. 

I’ll say that I liked this book much better than Suki, Alone, but it didn’t quite live up to Katara & the Pirate’s Silver.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('94b5799f-e9f7-4cff-b107-f75c68b10727', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'bba24540-4f27-43d8-877d-687c91def996', 4.0, NULL, NULL, 0, 8, 2022, '2022-08-04T12:00:00.000Z', '2026-03-17 23:32:33', 'In my second read of Faith Erin Hicks’ ATLA books, I was once again impressed with the dialogue & her ability to put the characters’ voices into her prose. 

As for the story, it was hit or miss with many more hits than misses. Suki was well-represented. It’s been a few years since I’ve read the first five entries, but I don’t remember much of her in them. The overarching story was very good! The idea of benders & non-benders having issues would make so much sense in that political climate. The one glaring weakness, however was the villain. Her motives were paper thin & it seemed like she just wanted to do bad things because she wanted to do bad things. I wasn’t really feeling that. Maybe I’m just spoiled by Zuko’s incredible motives in the greatest redemption arc in the history of visual media, but It’s the reason the book lost a star. 

The art was once again incredible! Along with the dialogue, it really felt like I was watching the show again. The colorist changing between books threw me off a little. Both were great, but the entire family changing hair colors was jarring. (Although the change was good. Redheads from the earth nation didn’t make very much sense.)

Overall, I enjoyed the book & I’ll be excited to reread the whole series after one of my annual rewatched sometime!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('c22648d3-5508-4fb6-9cd7-d9b62191f102', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'c255a4a8-2302-410f-80c7-4974a5955afe', 5.0, NULL, NULL, 0, 8, 2022, '2022-08-03T12:00:00.000Z', '2026-03-17 23:32:35', 'As much as I hate waiting months between volumes, I absolutely love reading this series through the IDW Collection. I haven’t disliked a single entry. 

This volume is the beginning of the writing change from Tom Waltz to Sophie Campbell. I had been warned that the quality dropped, but I must say I completely disagree. I don’t feel that she missed a single beat. It really just flowed from Waltz in a way that found me very impressed. Sure, it’s a little more emotional & has a few more characters that may come across as annoying (the kids, Mona Lisa, Jennika’s mini-series side characters), but I really feel they just added some heart to a part of this story that got pretty dark in all the right ways. 

I can’t think of too many comics that have me caring about characters on this level. And I can’t think of a single OTHER one that’s based on an IP. 

I recommend thoroughly that you go spend way too much money on these 14 volumes & let yourself fall in love with the Turtles one more time. You won’t regret it.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('83ee3bee-4563-4e71-aca0-b572199e1cdb', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '9396af76-c9f9-4ff4-b059-ac2b3602c3cf', 3.0, NULL, NULL, 0, 8, 2022, '2022-08-01T12:00:00.000Z', '2026-03-17 23:32:39', 'Don’t let the three star review fool you. I throughly enjoyed this read! It just has some issues for me that put it a bar below the rest of the collection. 

For starters, the series name is more accurate in this volume. This book is truly about Orion & Orion alone. And for the first half (& the last issue, which alone nearly made this a four star read for me), it was riveting. But most of the second half of the book it just felt like fluff & filler. I’ll admit that I was bored throughout this section. There were so many random characters that just show up for an issue or two about which I really couldn’t have cared less. The shining light of this section is the character development we see in Orion. The toll of the prophecy, the power, & the failure really push him into the final issue, which have I mentioned is phenomenal? 

All in all, it felt like a satisfying conclusion to 114 issues of Fourth World craziness into which Kirby, Byrne, & Simonson poured themselves & I’m glad it experienced this entire story at once!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('b12be4a6-8934-439c-8954-c3fe3953b1f8', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '212b9a5f-ac74-40d4-b053-3b73a7cca5d7', 4.0, NULL, NULL, 0, 7, 2022, '2022-07-28T12:00:00.000Z', '2026-03-17 23:32:43', 'I read this one directly after finishing the Jack Kirby omnibus and, I must say, I enjoyed it quite a bit more. 

Obviously, Kirby’s vision was brilliant as always, but the comic world wasn’t ready for the overarching story that he was trying to tell at the time. Byrne seems to have completed that concept for him. And I think he did it in exquisite fashion! 

Byrne brought these characters into the modern era in ways that felt natural. Characters like Orion, Darkseid, Mister Miracle, Bug Barda, Granny Goodness, Desaad, Kalibak, The Forever People, Metron, Highfather, etc., all felt like like products of the ‘70s & more like complex characters in their own rights, which is what Kirby was clearly trying to do two decades prior; in many ways, he had succeeded, despite everything fighting against him. 

The only negative I can find in these stories is the Genesis story arc. After the first two issues, I told my roommate how I was shocked to read an event that was actually good, then I read issues 3 & 4, which bored me to no end. This was only about ten years after Secret Wars & Crisis on Infinite Earth kicked off the concept of events in comic book universes (unless I’m overlooking something), which have become the bane of their existences since then. It was the only problem in an otherwise phenomenal run of comics & I’ve already started the Walt Simonson run on Orion!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('00dbf29e-a0b7-48ee-957c-2487bf8cdf56', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd3bad13c-41b4-4382-bbe8-1eb4dfbc9764', 4.0, NULL, NULL, 0, 6, 2022, '2022-06-16T12:00:00.000Z', '2026-03-17 23:32:46', 'I started reading Fourth World as a secondary read next to the book series I was currently reading. But by the end, I was really flying through it. 

I had been meaning to read the series for years & finally received it as a Christmas present last year. 

Long story short: this is the most I’ve ever enjoy a Bronze Age comic series. Granted, this is the defining series of the age. It begins & ends with Fourth World. 

It wasn’t perfect by any means. Those early issues of Jimmy Olsen & the beginning of Mister Miracle were ROUGH. But the series was held up in the beginning by Forever People & New Gods. The former started to slack just as Mister Miracle picked up & became very interesting. 

In a lot of ways, Fourth World was a product of its time. I have a hard time not cringing when an issue starts off with characters having far-too-detailed conversation of exposition with other characters that already know the information being given, but for the most part, this is just a really fun read! It has aged far better than most books for the same time period! 

Fourth World is a series that every single comic book reader should check off their list. I’ll be stepping directly John Byrne’s run & complete it with Walt Simonson’s Orion series. I’m definitely not burnt out from 59 issues of pure ‘70s campiness & that’s saying something!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('87dfa321-0773-4912-a9a6-2297cf637e77', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd52fe984-88a1-493e-908b-59754338508a', 4.0, NULL, NULL, 0, NULL, NULL, '2026-03-17T23:32:49.928Z', '2026-03-17 23:32:49', NULL, NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('959a892a-b19e-45fa-a640-9fd54b465f8f', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'aaf59507-34b1-47e0-ac77-52e4d8e12a5e', 4.0, NULL, NULL, 0, 3, 2022, '2022-03-30T12:00:00.000Z', '2026-03-17 23:32:51', 'I took a little break in the middle of this book to get some other things read, so it was quite a slow read for me 

Definitely much slower than it’s predecessor, The Well of Ascension is a highly character driven book, as compared to the plot heavy story of The Final Empire. 

It makes sense. After the excitement of a rebellion dies down, there’s time for the characters to switch their focus from external to internal. 

Some characters become even more likable to me (Elend, Sazed) while some characters became increasingly more frustrating (Vin), but I feel as though I know & understand them all much better after the second installment. 

Watching Elend start from the bottom to become the leader he needs to be in contrast to watching Vin start at the top & question why she was there was just the brilliant storytelling I’ve come to expect from Mr. Sanderson. 

It was also had some pretty big twists! One I saw coming; the other I did not at all. With this being a spoiler-free review, I’ll refrain from speaking further on these. 

I am excited to move on to the last (& best reviewed) book of the trilogy to tie up some loose ends & see how this story ends! I can’t remember the last time I loved a book series this much!', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('09bc378a-b097-4da1-9f29-5a1f3b8656a1', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '9e7336ac-1219-49ef-bb24-b696e38e2c8b', 3.0, NULL, NULL, 0, 3, 2022, '2022-03-08T12:00:00.000Z', '2026-03-17 23:32:55', 'I decided to read this book as part of a little personal study I’ve been doing on biblical love. It has been on my TBR list for quite a few years & it seemed short enough, so I went for it! 

Now, CS Lewis is one of my favorite classical authors & I was excited to delve into one more level of his nonfiction writing. I’ve always appreciated how he compares to modern Christian thinkers. I love how you can always tell that he put a lot of personal thought into his books rather than the modern practice of googling what other people think to put in your book & make money. 

That being said, this is my least favorite Lewis book in my collection so far. I’m not saying I don’t like it; j actually did like it quite a bit. My only issue is just how slow he is with the thoughts. The introduction was incredible, then we seemed to have four chapters of preparation to get to the Charity chapter. 

It was still an enjoyable enough read that any level of theological scholar should read at least once in their lives, but it didn’t live up to the Masterpiece that is Mere Christianity.', NULL, '', 0, 'user');
INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('6b02983c-6316-40ec-820a-1013edca41d2', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '5595208a-987f-43b2-b9ae-7d138813324d', 4.0, NULL, NULL, 0, 2, 2022, '2022-02-21T12:00:00.000Z', '2026-03-17 23:32:57', 'This is a spoiler free review for the entire series. 

I read the first volume of Seven to Eternity when it first came out. It didn’t really stick with me, so I didn’t consider the other volumes a priority when they were released. I owned volume two already for some reason and I bought volumes three & four when I saw them recommended to me on Amazon. Boy, I’m glad I did! 

Remender is my favorite comic book writer of all time. I’m used to his writing style. However, StE doesn’t fit quite into my expectations for him. 

I’m used to Rick writing very character heavy books. Fear Agent & Deadly Class will both sit on my top five list until the end of time for that very reason. However, I think this series really highlights Remender’s ability at worldbuilding. 

But this story that started out a testament to worldbuilding quickly became a character study for a hero & a villain that were both more than meets the eye. Neither likable, but both understandable. All other character simply existing as plot devices, these two became sentient beings that simply drew on your curiosities. 

The worldbuilding, the character studies, & the incredible art by Opeña (Seriously, somebody get this man on a Green Lantern book ASAP!) make this for a very worthwhile read!', NULL, '', 0, 'user');
