INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('5d0f72ae-9e49-4a0f-bda1-04dbd6f9d3e2', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '90e7cbd1-98e0-4513-94d2-52856804fa5c', 3.0, NULL, NULL, 0, 10, 2021, '2021-10-16T12:00:00.000Z', '2026-03-17 23:35:19', 'I’ve been a fan of Sam Miller since the early days of Paradise Fears. Since I enjoyed his debut novel (A Lite Too Bright) well enough, I figured I’d give his new book a chance. I preordered it, but it took about a year & a half to get to it on my reading list. 

I believe Sam could end up another John Green type, but his sophomore attempt once again was a mixed bag. 

While I enjoyed the premise & the character developed beautifully, there was a payoff that was lacking once again. 

I found the book hard to put down from Parts II-VI, but once the twist happened, I became much less invested. 

I feel there was opportunity to make this story more Twin Peaks than Riverdale. 

It’s really more my storytelling opinion. I did enjoy his first book more, but this book was certainly not bad & I look forward to his next work!', NULL, '', 0, 'user');
