INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('b03091f8-d814-408c-b84c-af3446f4b366', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '98dfc7e9-b8ee-415e-b00c-9512af2d123b', 5.0, NULL, NULL, 0, 11, 2019, '2019-11-01T12:00:00.000Z', '2026-03-17 23:35:41', 'I’m a fiction guy, so this review is not a common thing for me. I read this book in three sittings & it’s going to take some time for me to figure out exactly what I’m taking away from it, but it’s one of the most thought-provoking books I’ve ever read. 

I’m a huge fan of Comer from hearing him speak at a leadership conventions a few years ago. I’ve been an avid listener to his podcasts & i just love the way he puts thoughts together. 

I’ve been praying & searching for the reasons behind my unrest. Upon reading this book, God has really opened up my eyes to the fact that I’ve been in my own ways. Through biblical references, stories from his life, & helpful tips on habit-changing choices, Comer points us on a great direction to getting our souls back to being able to rest, which, if done correctly, can get us back to the One that created us in the first place. As he said, it’s not a book of answers, but of means to an end. And that end is Jesus & a content soul.', NULL, '', 0, 'user');
