INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('0b204e7f-c64a-4a7a-b096-1ce36eeffb37', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', 'd156b347-21aa-411e-aeab-1694abc060e5', 5.0, NULL, NULL, 0, 10, 2021, '2021-10-12T12:00:00.000Z', '2026-03-17 23:35:57', 'The reviews on this that I’ve read have been pretty startling. 

Here’s the thing you should know about sexual sin: it’s dark, gritty, & gory; it’s not for the faint of heart. 

If you’re unaware of that & don’t think you can handle that, don’t read this book. 

Also contrary to other reviews, the blame is never put on women. Not one single time. There are entire chapters dedicated to the fact that our masculine nature in a fallen world makes us more susceptible to sexual sin. 

But as a minister for middle & high school boys, I will say that this is the best material on sexual sin I’ve ever found. It’s full of practical tips that are rooted in biblical truth & scientific study. 

The only warning I have is that this book is heavily focused on marriage. If you’re a young man that sees marriage as far off into the future, then I’d recommend looking into Every Young Man’s Battle (which I have not read but plan to look into myself for a youth series with my boys).

But if you’re married, in a relationship, or at least of the age where marriage is on your radar, this is something I’d recommend fully! Especially those single adult men, as I believe it’s God’s call for us to learn to control our sexual desires before we’re entrusted with the heart & soul of a woman. 

I’m a fiction guy. There are a few pastors & theologians whose books connect with me. I don’t usually read nonfiction & actually connect with it, but some things are too important to avoid.', NULL, '', 0, 'user');
