INSERT INTO user_book_reviews (id, user_id, book_id, overall_rating, mood, mood_intensity, did_not_finish, finished_month, finished_year, created_at, updated_at, review_text, dnf_percent_complete, content_comments, is_anonymous, source) VALUES ('110b36d4-0764-4009-90bc-2a7d75b724df', '345dc32b-6a9d-4c34-81cf-c9a84fa17515', '02204e14-9723-4ba4-b01f-6ff7aa4e2b50', 4.0, NULL, NULL, 0, 10, 2021, '2021-10-09T12:00:00.000Z', '2026-03-17 23:35:59', 'Comer has, over the last few years, become one of my favorite Christian authors. Honestly, he’s one of the few I trust. I know we disagree on many small issues, but his foundation is sturdy & I appreciate that. 

He has a way of making the profound simple & the simple profound, which is a quality that is necessary to convey the gospel. 

My standards are a little high for him, since God Has a Name & The Ruthless Elimination of Hurry were masterpieces of theology & doctrine respectively. 

Did Live No Lies live up to those two books? Not quite. But I don’t think it’s completely fair to hold this book to that standard (Even though that’s the reason I give it four stars', NULL, '', 0, 'user');
